class T13Hitches{
	/*
		Hitches are costs or penalties that Characters and Descendants are afflicted with. They balance Annexes and are another form of Knot. As such they should be made from Proficiencies. Boon = Banes, Score = Marks, Draw = Ruins

		Anatomy:
		Hitch {
			"Name":["Basic Name","Full Name", "AKA list"],
			"Description":"A Description of the Hitch",
			"Proficiencies":[
				{"Type":"HitchType",Prof":{"Name":["Prof","Full Proficiency Name","Also known as the HitchType Proficiency"],"Description":"The Description of the Proficiency is defined here.", "Facet":"Awe", "ID":"#"}},
				{"Type":"Gnarl","Prof":{"Name":"First Gnarl","Description":"First Gnarl Proficiency Description","Facet":"Burden","ID":"#"}},
				{"Type":"Gnarl","Prof":{"Name":"Second Gnarl","Description":"Second Gnarl Proficiency Description","Facet":"Craft","ID":"#"}},
				{"Type":"Gnarl","Prof":{"Name":"Third Gnarl","Description":"Third Gnarl Proficiency Description","Facet":"Dominion","ID":"#"}}
				{"Type":"Trigger","Prof":{"Name":"First Trigger","Description":"First Trigger Proficiency Description","Facet":"Enigma","ID":"#"}},
				{"Type":"Trigger","Prof":{"Name":"Second Trigger","Description":"Second Trigger Proficiency Description","Facet":"Fury","ID":"#"}},
				{"Type":"Trigger","Prof":{"Name":"Third Trigger","Description":"Third Trigger Proficiency Description","Facet":"Gossamer","ID":"#"}},
				{"Type":"Slot",Prof":{"Name":"First Additional","Description":"First Additional Proficiency - This may be acting as a Nimbed, Umbral or Tangle due to some odd choices in Gnarl, etc.","Facet":"Heresy","ID":"#"}},
				{"Type":"Slot","Prof":{"ID":1202}},
			],
			"Bane":(number between 1 and 50)
		}


	*/




