		array('Name'=>'Dull','AKA'=>'Boring, Simple, Stupid, Tedious, Shallow, Dense, Ignorant, Flat, Featureless, Listless, Placid, Blank, Slack, Depressing, Dismal, Dreary, Dry, Humdrum, Ordinary, Uninspiring, Unimaginative, Prosaic, Hackneyed, Commonplace, Common, Monotonous, Colourless, Tasteless, Soporific, Vapid, Unexciting, Lackluster, Methodical, Slow, Aged, Conservative', 'Facet'=>'Miasma', 'Specify'=>1, 'HitchType'=>4, 'Description'=>'Some Characters and Descendants are just not very exciting, others seem to have refined being boring, or unimaginative into an art form.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
