		array('Name'=>'Unchanging','AKA'=>'Constant, Consistent, Permanently ..., Cannot Update, Eternal, Immutable, Enduring, Continuing, Continuous, Perpetual, Static, Unvarying, Still, Lasting, Immortal, Unageing, Unsupported, Out-dated, Timeless, Overgrown, Senile, Bigoted, Conservative, Neo-phobic, Scared of Change, Unlearning', 'Facet'=>'Miasma', 'Specify'=>1, 'HitchType'=>7, 'Description'=>'Some Descendants don&#39;t update or change, even if you&#39;d like them too. This can be especially true of Location and Pact Descendants, eventually thought they do just seem to fade away.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Onerous','AKA'=>'Arduous, Burdensome, Cumbersome, Demanding, Difficult, Exhausting, Gruelling, Harsh, Laborious, Oppressive, Painful, Severe, Strenuous, Taxing, Troublesome, Heavy, Galling, Irksome, Tiresome, Right-Wing', 'Facet'=>'Miasma', 'Specify'=>1, 'HitchType'=>8, 'Description'=>'Some people and Descendants are just hard work to be around. They are so much trouble they almost aren&#39; worth it. That&#39;s a good time to use an Onerous Hitch.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Doldrums','AKA'=>'Bored with ..., Bored, Malaise, In a Slump, Stagnated, Apathy, Blah, Blue, Boredom, Dejected, Downer, Down in the Dumps, Listless, Moping, Tedium, Torpor, Yawns, Sunk Cost Fallacy, Pointless, Weed-Infested', 'Facet'=>'Miasma', 'Specify'=>1, 'HitchType'=>9, 'Description'=>'Doldrum Hitches indicate someone or something caught in a boring or repetitive task or situation. Doldrums can indicate sunk cost fallacies and general malaise.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Inert','AKA'=>'Immobile, Impotent, Inactive, Motionless, Paralysed, Powerless, Dead ..., Broken ..., Numb ..., Unresponsive, Out of ...', 'Facet'=>'Miasma', 'Specify'=>1, 'HitchType'=>10, 'Description'=>'A Descendant with an Inert Stagnation Hitch tends to not work at all, even when it does work, it sometimes doesn\'t work right.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Dying/Dead','AKA'=>'Dead, Dying, Fading, Moribund, Declining, Disintegrating, Ebbing-Away, Slipping-Away, Perishing, Sinking, Vanishing, "At Death\'s Door", Done For, "One Foot in the Grave", Deceased, Late, Lifeless, Departed, Stiff, Bereft of Life, Bought The Farm, Breathless, Cadaverous, Defunct, Mortified, Extinct, Erased, "Gone to Meet ... Maker", No More, Offed, "Out of ... Misery", Pushing Up the Daisies, Resting in Peace, RIP, F in Chat, Bled Out, Butchered, Decapitated, Hanged, Drawn and Quartered, Ended', 'Facet'=>'Nature', 'Specify'=>1, 'HitchType'=>0, 'Description'=>'Dying/Dead is what happens at the end of a normal life. It is the usual Hitch that Mortal Wounds create, and is the worst of the Scarred Hitches.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Tattooed','AKA'=>'Birthmark, Pierced, Piercings, Tattoo, Facial Tattoo, Large Tattoo, Excessive Tattoos, Tattooed ..., Inked, Bad Tattoos, Distinctive Tattoo, Facial Piercings, Branded, Scarred, Decorative Scars, ', 'Facet'=>'Nature', 'Specify'=>1, 'HitchType'=>1, 'Description'=>'Tattoos are an artistic or culturally applied decorative scar. In some cultures simply having a tattoo can be a hitch itself, in others the tattoo will have to be extreme somehow.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Trauma','AKA'=>'Severe Pain, Traumatised by ..., Shocked, Stressed by ..., Confused, Tortured by ..., Long-Term Suffering, Mental Trauma, Psychic Trauma, Post-Traumatic Stress Disorder, PTSD Sufferer, Old Injuries, Scars, Old War Wound, Nightmares, Phantom Limb, Broken ... Bone, Surgical Scars, Battle Scars', 'Facet'=>'Nature', 'Specify'=>1, 'HitchType'=>1, 'Description'=>'Trauma Hitches are amongst the worst Scar Hitches, it can describe Emotional, Psychic, or Physical Traumas.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Pain','AKA'=>'Continual Pain, Old Injuries, Aches and Pains, Toothache, Headaches, Burns, Arthritis, Muscular Pain, Joint Pain, Bone Pain, Sporadic Pains, Stabbing Pains, Strong Food Intolerance, Crohn\'s Disease, Pox-Victim, Agony, In Agony from ...', 'Facet'=>'Nature', 'Specify'=>1, 'HitchType'=>2, 'Description'=>'Pain Scar Hitches are incredibly common, many a veteran will complain of an old injury bothering them in inclement weather.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Disfigurement','AKA'=>'Facial Scars, Missing ..., Lost ..., Burns, Nightmares, Disturbed ..., ', 'Facet'=>'Nature', 'Specify'=>1, 'HitchType'=>3, 'Description'=>'Some Scars are worse than others. Disfigurement Hitches can include missing body-parts (from eyebrows, teeth, fingers, toes, to ears, noses, eyes, legs or arms), facial scars, burns and psychological hang-ups too.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Emotional Scars','AKA'=>'Nightmares, Trembling, Nervous, Nerve Damage, Emotional Trauma, Psychological Scars, Night-Terrors, "Wakes Screaming", Disturbed Sleep, Sleepwalker, Bad Dreams, No Dreams, Cannot Remember Dreams, Memory Blocks, Repressed Memories, Emotionally Unstable, Screwed-up, Messed-up, Unsettled by ..., Distracted by ..., Disturbed by ..., Upset by..., Stigma', 'Facet'=>'Nature', 'Specify'=>1, 'HitchType'=>4, 'Description'=>'Not all injuries are physical so not all Scar Hitches leave visible marks.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Stress','AKA'=>'Anxious about ..., ... Anxiety, Pressure from ..., Apprehensive about ..., Tense about ..., Tense from ..., Trepidation about ..., Worried about ..., Screwed-up by ..., Disturbed by ..., Troubled by ...', 'Facet'=>'Nature', 'Specify'=>1, 'HitchType'=>5, 'Description'=>'Stress Hitches are effectively Social Scars. Unlike most Scarred Hitches, Stress can, and does, spread. Stress unlike most Social Hitches is usually caused by some Trauma or experience in the originator.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Limited Mobility','AKA'=>'Dislocated ..., Broken ..., Frozen Joint, "Hurts when I Move", Torn Ligament, Damaged Rotator Cuff, Limps, Stiff ..., Stiffened ..., Lame, Gimpiness, Hobbling, Stumbling, Crawling, Lumbering, Sprained ..., Teetering, Tottering, Struggles to ..., Plodding, Strained ..., Cramped ..., Cramp, Suffering, Staggering, Winded by ..., Recuperating from ..., ', 'Facet'=>'Nature', 'Specify'=>1, 'HitchType'=>6, 'Description'=>'Limited mobility Scarred Hitches can occur whenever you scar a joint or muscle group, they act as a blockage on the movement of the joint or muscle, and share a lot in common with Fatigued Hitches.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Damaged','AKA'=>'Impaired, Bent, Busted, Dinged, Hurt, Marred, Shot, Sunk, Beat-Up, Glitched, Needs Repair, In Poor Condition, Messed-up, "On The Blink", "Out of Action", "Out of Order", "Screwed Up", Damaged ..., Broken ...', 'Facet'=>'Nature', 'Specify'=>1, 'HitchType'=>7, 'Description'=>'Damaged Hitches are the Descendant version of Scarred Hitches.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Brand','AKA'=>'Marque, Trademark, Label, Logo, Company Name, Commercial Branding, Marked with ..., Stained ..., Blaze, Unique Scar, Scorched ..., Branded with ..., Branded by ..., Corporate Tattoo, Whipped by ..., Flogged for ..., Burnt by ..., Sponsored by ..., Emblazoned with ...', 'Facet'=>'Nature', 'Specify'=>1, 'HitchType'=>8, 'Description'=>'Brands can either be a burn, scorched into the flesh of cattle or criminals, or it might be the trademarks, logo, or name of a company.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Debts','AKA'=>'Indebted to ..., Repaying ..., Borrowed from ..., Loaned from ..., Debtor, Credit with ..., Mortgage, Secured Loan, In Arrears, "Cheque is in the Mail", Owes Money, Bankrupt, Financially Obligated', 'Facet'=>'Nature', 'Specify'=>1, 'HitchType'=>9, 'Description'=>'Debts are largely economic Scars, lingering costs of financial disasters in the Character\'s pasts.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Faulty','AKA'=>'Defective, Inaccurate, Imperfect, Malfunctioning, Incorrect, Flawed, Erroneous, ... Defect, Disabled ..., Leaky, Unrepairable, Out-of-Control, Erratic, ', 'Facet'=>'Nature', 'Specify'=>1, 'HitchType'=>10, 'Description'=>'Faults are caused by accumulated tiny damage from everyday use, or develop after severe mistreatment. Faulty Descendants may not work often, or erratically, they might be more powerful than intended or weaker than normal. Occasionally they may have new uses because of a Fault.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Paranoid','AKA'=>'Paranoiac, Delusions of Persecution, Suicidal, Delusional, Overly Suspicious, "They Bug The Phones", "Do you hear them too?", "Of course the Government know all about it", "Science is trying to destroy God", "The Angels tell me that God has targeted me", "I hear you laughing at me!", "They think I don\'t know what they are up to", "Vaccines damage children, everyone knows that", "You think they care about the little guy?", "What did you do with my keys?", "What did they say about me?", "That duck is staring at me", "This restaurant doesn\'t have the regulation number of fire exits, it\'s a death trap, we have to get out of here!", "I\'ll just check it again", "You have no idea what you have gotten involved in", "You\'re planning on leaving me, I know it!", "Run!"', 'Facet'=>'Orthodox', 'Specify'=>1, 'HitchType'=>0, 'Description'=>'The Paranoid Hitch is the worst of the Paranoia Hitches. The truly Paranoid mind will destroy the body, or itself during a bad episode.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Suspicious','AKA'=>'Doubtful, Suspicious of ..., Cautious, Skeptical, Wary of ..., Mistrustful, Watchful, Cagey, Quizzical, Faithless, Suspecting ..., Distrustful, "What do you want?", "What are you doing here?", "Everyone is guilty of something", "Did I close that?", "Trust should be earned not given", "Stop or I will shoot!", "Hands where I can see them!", "I don\'t trust anyone"', 'Facet'=>'Orthodox', 'Specify'=>1, 'HitchType'=>1, 'Description'=>'Sometimes Paranoia is just a mild, but persistent suspicious nature. This is the Hitch suitable for any number of grizzled cops and hard-boiled detectives.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Far-fetched','AKA'=>'Doubtful, Dubious, Eccentric, "Some thing about it is fishy", "Hard to swallow", Illogical, Preposterous, Queer, Incredible, Straining Credulity, Strange, Unconvincing, Unbelievable, Unrealistic, Weird, "Well, the President doesn\'t need to know about it", "What part of Secret Cabal do you not understand?", "Everyone knows all world-leaders are paedophiles", "Aliens are actually time-travellers", "Aliens are really just Demons", "Objective Reality? That\'s just in your head, you know?", "The Oil Cartels control the weather via the Navy\'s HAARP experiments", "Ancient human\'s had Space-flight, but the Aliens destroyed the civilization."', 'Facet'=>'Orthodox', 'Specify'=>1, 'HitchType'=>2, 'Description'=>'Sometimes Paranoia can show an obvious separation from reality, other-times they can just be a few hard to believe ideas. This Hitch is for Characters that suffer from the latter.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Mistrustful','AKA'=>'Cynical, Skeptical, Cautious, Hard to Trust, Jealous, Sly, Treacherous, Untrustworthy, Trust-less, Untrustworthiness, Undependable, Shady Character, Shifty, Tricky, Deceitful, Insincere, Untruthful, Unsympathetic, Unlikeable, Contemptuous, Incredible, Hypocritical, Unveracious, Incorrigible, Loathsome, Evasive', 'Facet'=>'Orthodox', 'Specify'=>1, 'HitchType'=>3, 'Description'=>'Mistrustful Hitches are for those Characters who find it hard to trust others, or hard to gain trust.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Wary','AKA'=>'On Guard Against ..., Watchful for ..., Watching for ..., Precautionary against ..., Circumspect about ..., Vigilant for ..., Hyper-vigilant about ..., Attentive to ..., Cagey about ..., Timid around ..., Anxious about ..., Hyper-aware of ..., Mindful of ..., Overwary about ..., Pessimistic about ..., Perturbed by ..., Alert for ...', 'Facet'=>'Orthodox', 'Specify'=>1, 'HitchType'=>4, 'Description'=>'Wary Hitches are generally appropriate for cautious Characters. Their Paranoia should be directed against a specific thing.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Cautious','AKA'=>'Careful, Overly Careful, Overcautious, Timid, Cagey, Guarded, Unadventurous, Conservative, Hesitant, Reticent, Vigilant, Watchful, Prudent, Cautioned, Nervous, Suspicious, Tentative, Leery', 'Facet'=>'Orthodox', 'Specify'=>1, 'HitchType'=>4, 'Description'=>'The Character is just generally cautious, ', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Conspiracy Theory','AKA'=>'"New World Order", "Black Helicopters", "Chemtrails", "Vaccines cause Autism", "They have a cure for Cancer", "JFK was killed by the CIA", "False Flag Operations" , "The Earth is Flat", "Moon Landings" , "The Freemasons are behind it all", "Protocols of the Elders of Zion", "Papist? Pagan more like!", "The Antichrist walks amongst us", "Satan made me do it", "Secretly a ...", "Area 51, Hanger 18, Saucer Crashes...", "Cattle Mutilations, UFOs or Satanists?", "Illuminati", "Cognoscenti", "False History", "Sports Events are rigged"', 'Facet'=>'Orthodox', 'Specify'=>1, 'HitchType'=>5, 'Description'=>'Conspiracy Theories are like Conspiracies, but aren\'t true. They generally consist of a belief that all events are caused by deliberate actions by mysterious groups, rather than random accidents and incompetence. Everything is part of some specific plan (often with a tenuous historical veracity at best). You should specify the specific Conspiracy that the Character believes in.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Delusional','AKA'=>'Unrealistic Beliefs, Fringe Science, Pseudo-Science, Fringe religion, Religious Cult, New Age Beliefs, Deranged, Senile, New Thought, Theosophical Thinking, Holistic Thinker, Alternative Medicine Practitioner, Quantum Wooer, "That\'s what they want you to think"', 'Facet'=>'Orthodox', 'Specify'=>1, 'HitchType'=>6, 'Description'=>'Everything you learned growing up is just, like, what they wanted you to learn, man. They control the education system man, why do you think you\'ve never heard about this stuff?', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Irrational','AKA'=>'Illogical Features, Freaky Fault, Kooky Contraptions, Weird Science, Magical-Technology, Magi-tech, Alchemical Technology, Hinter-Tek, Psiber-Technology, Peculiar Peripheral, Absurd Appliance, Crazy Component, Wacky Widget, Unreasonable Utensil, Irrational Apparatus, Preposterous Object, Paranoid Products', 'Facet'=>'Orthodox', 'Specify'=>1, 'HitchType'=>7, 'Description'=>'The Irrational Hitch is intended for Descendants that fail to behave in accordance with logic. They might have strange, even ridiculous features, faults or foibles.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Delusionary','AKA'=>'Abstract ..., Fanciful ..., Fantastical ..., Fictional ..., Hypothetical ..., Imagined ..., Theoretical ..., Unreal ..., Whimsical ..., Visionary ..., Apocryphal ..., Sees Apparitions, Chimerical ..., Dreamed, Dreamy, Dreamlike ..., Fabulous ..., Hallucinatory ..., Illusory ..., Non-existent ..., Phantasmal ..., Quixotic, Spectral ..., Unsubstantial ...', 'Facet'=>'Orthodox', 'Specify'=>1, 'HitchType'=>8, 'Description'=>'The Delusionary Hitch is intended for Paranoid Characters who start to see and act on their delusions, or Descendants and Characters who don\'t actually exist.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Precautions','AKA'=>'Preventative Measure for ..., Careful about ..., Caution about ..., Insurance against ..., Made Provisions Against ..., Safeguarding, Safety Measures, "Discretion is the better part of valour", "Forethought is better than regret"', 'Facet'=>'Orthodox', 'Specify'=>1, 'HitchType'=>9, 'Description'=>'Paranoid people often spend money and time on actions that seem odd to others, but are genuine precautions against some disaster or another. Paying for insurance, for example seems like paranoia until something happens.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Burns the Evidence','AKA'=>'Implosion, Self-destructing, Self-deleting, "Remove all records", "Scrub everything", "Cleanse the area", "Professional Criminal", Decontamination, "No Witnesses", "Nothing Personal", False Fronts, "Leave No Traces", "Tidy the area"', 'Facet'=>'Orthodox', 'Specify'=>1, 'HitchType'=>10, 'Description'=>'Sometimes a paranoid hacker might make his code self-delete when it is done. Or a paranoid Spy&#39;s message might self-destruct with a wisp of smoke.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Diseased','AKA'=>'Afflicted with ..., Ailing Health, Infected with ..., Infirm, Sickly, Sick with ..., Infectious, Unwell, Unhealthy, Ill with ..., Suffering from ..., Affected  by ...', 'Facet'=>'Phoenix', 'Specify'=>1, 'HitchType'=>0, 'Description'=>'Diseased Characters are infected and dying. This of course makes them very Fatigued.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Weary','AKA'=>'Bored with ..., Weary of ..., Exhausted by ..., Fatigued by ..., Impatient for ..., Jaded with ..., Overworked, Discontented, Flagging, Spent, "Sick and Tired of ...", Done with ...', 'Facet'=>'Phoenix', 'Specify'=>1, 'HitchType'=>1, 'Description'=>'Weary Characters are not necessarily tired or otherwise Fatigued, but they become impatient with others more easily as well.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Exhausted','AKA'=>'Drained by ..., Exhausted by ..., Introverted, Extroverted, Frazzled by ..., Drained by ..., Depleted ..., Dissipated ..., ... Spent', 'Facet'=>'Phoenix', 'Specify'=>1, 'HitchType'=>2, 'Description'=>'The Exhausted Hitch is for Hitches where the Character is Fatigued by the Specified thing. As an example, the Introverted are exhausted by Social situations.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Blasé','AKA'=>'Nonchalant, Nonchalant about ..., Fed up with ..., Bored of ..., Disenchanted with ..., Done it all, Knowing, Jaded, World-weary, Worldly, Experienced, Mature, Refined ..., Cultivated ..., Practical ..., Seasoned ..., Cynical, Skeptical, Streetwise, Suave', 'Facet'=>'Phoenix', 'Specify'=>1, 'HitchType'=>3, 'Description'=>'The Blasé Hitch is intended for those Characters who have such wide experience that they have seen everything before. You can specify an area of experience that the Character is particularly Blasé about, but you don\'t have to. Remember that these are Hitches, and work against the Character, not letting them be Optimistic, or even realistic as they are so Blasé about things.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Fever','AKA'=>'Pyrexia, Elevated Temperature, Shivering, Flushed, Sweating, Pneumonia, Typhus, Meningitis, Malaria, Sepsis, Infected Wounds, Seasonal Flu, Infections, Surgical Fever, Cancerous Fever, Gout, Metabolic Disorder', 'Facet'=>'Phoenix', 'Specify'=>1, 'HitchType'=>4, 'Description'=>'Fevers are common to many diseases, but work particularly well as a Fatigued Hitch. The type of Fever can vary greatly between Characters, some being short, others permanent.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Contagious','AKA'=>'Infectious Disease, Spreading ..., Transmissible ..., Communicable Effect, Infection Vector, Diseased, Infected with ...', 'Facet'=>'Phoenix', 'Specify'=>1, 'HitchType'=>5, 'Description'=>'The Contagious Hitch is ideal for Characters that have an on-going contagious disease. The disease might not itself be very deadly, but it spreads easily to others.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Overworked','AKA'=>'Stress-related Illness, Overburdened by ..., Overtaxed, Stressed by ..., Stressed Out, Under Stress, Overwrought with ..., Burned-Out on ..., Distressed by ..., Abused by ..., "Taken Advantage Of by ...", Shabby, Tattered, Well-Worn, Stale, Cliché, Shop-worn, Hackneyed, Hokey, Cornball, Corny, Uninspired ..., Vapid, Stock ..., Stereotypical ..., Routine ...', 'Facet'=>'Phoenix', 'Specify'=>1, 'HitchType'=>6, 'Description'=>'Overworked people tend to make mistakes in their work, as though they were blocked somehow. They also tend to get ill, or at least not get better quickly when they are. Even some ideas can become over-worked, abused, or commonplace, creating Cliches and Stereotypes.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Unpractised','AKA'=>'Unpractised at ..., Unpractised with ..., Inexperienced at ..., Inexperienced with ..., Amateur ..., Callow ..., Fresh ..., Green, Ignorant of ..., Immature, Child, Inept at ..., Inexpert at ..., Unaccustomed to ..., Naive about ..., Rookie ..., Unseasoned ..., Unsophisticated, Untrained at ..., Untrained with ..., Virgin ..., Young, New ..., Undemonstrated ..., Unproved ..., Unproven ..., Untested, "Hasn\'t read the manual", "First Time"', 'Facet'=>'Phoenix', 'Specify'=>1, 'HitchType'=>7, 'Description'=>'Sometimes a Character is Fatigued, not by disease or mentally, but simply because they are not very good at what they are trying to do. This is best portrayed by the Unpractised Hitch. Just remember to Specify what you are unpractised in. When a Descendant has an Unpractised Hitch it means the owner cannot get the practice in.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Tiring','AKA'=>'Demanding, Exacting, Taxing, Exhausting, Heavy, Bulky, Overly-critical, Difficult to use, Hard to learn, Hard Work, Onerous, Strict, Stringent, Tough, Trying, Backbreaking, Bothersome, Oppressive, Weighty', 'Facet'=>'Phoenix', 'Specify'=>1, 'HitchType'=>8, 'Description'=>'Tiring Hitches tire the Character out. This can be useful if using a Descendant should be very tiring... obviously.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Over-worked','AKA'=>'Belaboured, Undervalued, Pressured by ..., Overloaded with ..., Overburdened by ..., Misused by ..., Overtaxed by ..., "Beating a Dead Horse", "Sweat and Slave Away", "Pulls All-Nighters", "Working Night and Day", Workaholic, Exploited by ..., Wasted by ...', 'Facet'=>'Phoenix', 'Specify'=>1, 'HitchType'=>9, 'Description'=>'The Over-worked Hitch indicates someone or something that is constantly tasked with another job. Often this results in reducing how well the Hitched Descendant or Character can work on other things.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Obsolete','AKA'=>'Antiquated, Archaic, Out-of-Date, Outmoded, Ancient, Antique, Dated, Discarded, Disused, Dusty, Has-Been, Moth-eaten, Mouldy, Old, Old-Fashioned, Old-Hat, Old-School, Out-of-Fashion, Aged, Passé, Stale, Superannuated, Time-worn, Unfashionable, Scrapped, "Behind the Times", Vintage, Out-of-Style, Olden, Musty, Unstylish', 'Facet'=>'Phoenix', 'Specify'=>1, 'HitchType'=>10, 'Description'=>'Sometimes the equipment that you have is a little old, sometimes it needs an update, other times it is completely obsolete. Perhaps it is so old it is actually just a rusted scrap, or maybe it can do something that modern devices just can\'t any more.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Consume','AKA'=>'Consumes ..., Devours ..., Eats ..., Drinks ..., Ingest ..., Absorb ..., Inhales ..., Smokes ..., Swallows ..., Partakes of ..., Gorges on ..., Hungers for ..., Always Hungry, Thirst for ..., Must Regularly Consume ...', 'Facet'=>'Quiet', 'Specify'=>1, 'HitchType'=>0, 'Description'=>'This Dependence Hitch means the Character or Descendant must consume something or be wounded. Specify the <q>food</q> that the Hitch requires, such as Zombies having a Consume (Brains) Hitch. You might assume a Consume Hitch triggers at least 3 times a day, but usually is only triggered when an opportunity to consume the Specified <q>food</q> occurs, and they try to reset, or once a day if they have not consumed it yet that day.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Addicted','AKA'=>'Addicted to ..., Accustomed to ..., Hooked on ..., Habituated to ..., Dependant on ..., Under the Influence of ..., Space out on ..., Strung out on ..., Tweaked on ..., Junkie, ... Fiend, ... Freak, ... Hound, Alcoholic, Chainsmoker, Coffee Achiever, ... Head, Lust for ..., Wanderlust, Cannibal', 'Facet'=>'Quiet', 'Specify'=>1, 'HitchType'=>1, 'Description'=>'This Dependence Hitch is meant for those Addictions that are not as terrible as a Consume Hitch, but can still make life very difficult for the Character. These Hitches are usually triggered if the Character has not been able to take their substance of Choice in any day (although longer periods ', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Habit','AKA'=>'Habit of ..., Tendency to ..., Practice of ..., Practices ..., Behaviour Pattern of ..., Routine of ..., Bias to ..., Penchant for ..., Inclination to ..., Inclination for ..., Propensity for ..., Weakness for ..., Wanderer, Custom of ..., Lax, Needs ..., Red-tape, Bureaucracy, Procedures, Habitual', 'Facet'=>'Quiet', 'Specify'=>1, 'HitchType'=>2, 'Description'=>'A Habit Hitch is a Dependence upon a behaviour, rather than a substance.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Ambition','AKA'=>'Ambition for ..., Ambition to ..., Romantic, Thirst for ..., Lust for ..., Desire for ..., Desire to ..., Aspiration to ..., Aspiring ..., Wants to be a ..., "Fake it till you make it"', 'Facet'=>'Quiet', 'Specify'=>1, 'HitchType'=>3, 'Description'=>'Ambition Hitches drive a Character onward and upward. Whether they want to be President, Rich, King, a God or just to get a job, it doesn&#39;t really matter.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Attached','AKA'=>'Thralled by ..., Thralled to, In Love with ..., "Lead by the nose", "Puppet of a greater power", Co-Dependant on ..., Co-Dependant with ..., Dependant on ..., Fixated on ..., Connected to ..., Linked to ..., Stuck to ..., Handcuffed to ..., Surgically attached to ..., Implanted ..., Affiliated with ..., Alliance with ..., Associated with ..., Joined forces with ..., Signed up with ..., Signed to ..., ', 'Facet'=>'Quiet', 'Specify'=>1, 'HitchType'=>4, 'Description'=>'Attached Hitches are used for all those times a Character is stuck with something they shouldn&#39;t be. Maybe they are handcuffed to a suspect, are in a co-dependant relationship, or maybe they are literally the puppet of a greater power.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Routine','AKA'=>'Bureaucracy, Conventional, Ordinary ..., Regularly ..., Unremarkable, Familiar, General, Plain, Standard, Methodical, Typical, Practices ..., Procedure, Formulaic, Shtick, "Stuck in a rut"', 'Facet'=>'Quiet', 'Specify'=>1, 'HitchType'=>5, 'Description'=>'Routine Hitches are the bane of spontaneous Characters. Some people like routine, and it tends to spread. Bureaucracy is a fine example of a Government with a Routine Hitch.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Wild','AKA'=>'Barbarian, Barbaric, Berserk, Primitive, Savage, Feral, Foolhardy, Hysterical, Impetuous, Imprudent, Incautious, Lawless, Outrageous, Overgrown, Rabid, Rampant, Rash, Reckless, Riotous, Rough, Rude, Uncivilised, Uncultivated, Undisciplined, Undomesticated, Unruly, Vicious, Violent', 'Facet'=>'Quiet', 'Specify'=>1, 'HitchType'=>6, 'Description'=>'Wild Hitches are favoured by party-animals and various addicts, this represents a blockage towards living a "Quiet" life.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Contingent','AKA'=>'Contingent on ..., Conditional, Chance to ..., Dependent on ..., Probably ..., Only if ..., Depends on ..., If it is ..., Not if ..., Never unless ...', 'Facet'=>'Quiet', 'Specify'=>1, 'HitchType'=>7, 'Description'=>'Contingent Hitches can stop Characters or Descendants from doing much of anything unless the weather is right, or the public votes a certain way, it always depends on something else, usually uncontrollable and external to the situation at hand.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Craving','AKA'=>'External Power Source, Battery-powered, Mains-power, Must be reloaded, Ammunition Required, Needs ..., Fuelled by ..., Powered by ..., Feed ..., Sustained by ..., Craves ..., ... Supply, "Fill her up", "Fill it up", "Gas up", "Top-up", Longing for ..., Yearning for ..., Urge to ..., Appetite for ...', 'Facet'=>'Quiet', 'Specify'=>1, 'HitchType'=>8, 'Description'=>'Craving Hitches are the way to handle a Descendant or Character that just needs a little something every now and then. It might be batteries, an external power source, or human souls.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Wasteful','AKA'=>'Expensive, Expensive Taste, Inefficient, Profligate with ..., Wasteful of ..., Wastes ..., Reckless, Lavish, Immoderate, Improvident, Prodigal, Spendthrift, Squanders ..., Squandering, Uneconomical, Wanton', 'Facet'=>'Quiet', 'Specify'=>1, 'HitchType'=>9, 'Description'=>'Some things are just plain wasteful. No matter how well they succeed or perform at a task, they accrue extra costs, usually from problems like fuel inefficiency or expensive tastes.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Reliance','AKA'=>'Confident in ..., Depends on ..., Reliant on ..., Relies on ..., Has Faith In ..., Puts Stock In ..., Trusts ..., Gives Credit to ..., Credits ..., Dependent on ..., Subject to ..., Sustained by ..., Regulated by ..., Controlled by ..., Liable to ...', 'Facet'=>'Quiet', 'Specify'=>1, 'HitchType'=>10, 'Description'=>'Reliance on something or someone can have unpredictable results, especially when things go wrong and they let you down.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Protective','AKA'=>'Careful of ..., Defensive about ..., Possessive of ..., Vigilant for ..., Safeguarding, Preservative, Custodial, Custodian, Guardian, Guards ..., Protects ..., Bodyguard for ...', 'Facet'=>'Rook', 'Specify'=>1, 'HitchType'=>0, 'Description'=>'If you want a Character to throw themselves in harms way over and over then consider giving them a Protective Hitch, specify who or what they protect, or why.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Belligerent','AKA'=>'Aggressive towards ..., Antagonistic to ..., Bellicose, Combative, Contentious, Hostile to ..., Ornery, Quarrelsome, Mean, Militant about ..., Cantankerous, Fierce, Hot-Tempered, Quick to Anger, Angry, Truculent, "Chip on the shoulder", "Has a bone to pick with ...", Blames ...,', 'Facet'=>'Rook', 'Specify'=>1, 'HitchType'=>1, 'Description'=>'Belligerent Hitches are a great choice for any sort of militant or aggressive Characters. You can specify what the Character is belligerent about or how they are belligerent.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Irritable','AKA'=>'Irritated by ..., Bad-Tempered, Annoyed by ..., Exasperated by ..., Fractious, Petulant, Prickly, Resentful, Surly, Testy, Brooding, Cantankerous, Cross about ..., Crotchety, Crabby, Complains about ..., Easily Offended, Gloomy, Grouchy, Grumbles about, Hasty, Huffy, Hypercritical, Ill-humoured, Irascible, Moody, Morose, Over-sensitive, Snowflake, Peevish, Querulous, Quick-tempered, Sensitive to ..., Snappy, Snarls at ..., Snaps at ..., Tense, Touchy about ...', 'Facet'=>'Rook', 'Specify'=>1, 'HitchType'=>2, 'Description'=>'The most common of the Defensive Hitches is the Irritable Hitch, almost any Character can be irritable, especially if you specify when tired.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Vigilant','AKA'=>'Vigilant for ..., Attentive towards ..., Attentive of ..., Anxious about ..., Aware of ..., Cautious of ..., Cautious about ..., Circumspect, Keen, Observant of ..., Wary of ..., Alert for ..., Guarded about ..., Looking for ..., Looking to ..., On Alert, On Guard, On the Ball, On the Job, On the Lookout, Open-eyed, "Sleeps with one eye open", Sharp, Sleepless, Unsleeping, Unrelenting, Ceaseless, Wakeful, Wide-Awake, Keeps Their Eyes Peeled for ..., Expecting ..., Awaiting ..., Waiting for ...', 'Facet'=>'Rook', 'Specify'=>1, 'HitchType'=>3, 'Description'=>'Vigilant Hitches seem at first to not be a Hitch, but wait until you have been up for three days, and still can not bring yourself to sleep because you believe alien invaders are creeping around outside.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Hypersensitive','AKA'=>'Hypersensitive to ..., Nervous of ..., Responds Negatively to ..., Susceptible to ..., Easily Affected by ..., Weakness to ..., High-Strung, Emotional, Supersensitive, Precarious, Capricious, Erratic, Headstrong, Impatient, Mercurial, Thin-skinned, Snowflake, Easily Upset, Neurotic, Ticklish, Touchy about ..., Delicate, Easily Bruised, Inflamed, Raw Nerves, Easily Hurt by ..., Soft, Ultrasensitve, Believes they are Allergic to ..., Intolerance to ..., Intolerant of...', 'Facet'=>'Rook', 'Specify'=>1, 'HitchType'=>4, 'Description'=>'The Hypersensitive Hitch is, if some are to be believed, the choice of the next generation. Hypersensitive Characters are easily triggered by specified events, behaviours or substances. A Hypersensitivity to noise might make a Character to wear earplugs for a normal life, etc. This is where Defensive Hitches crossover somewhat with Offensive and Vulnerability Hitches.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Uptight','AKA'=>'Anxious about ..., Apprehensive of ..., Cautious about ..., Edgy, Uneasy, Concerned about ..., Nervy about ..., Nervous of ..., Old-fashioned, Defensive, Strict, Tense, Troubled by ..., Withdrawn, Worried about ...', 'Facet'=>'Rook', 'Specify'=>1, 'HitchType'=>5, 'Description'=>'Uptight Characters can spread their particular blend of social defensiveness to other people, making others as cautious or fun sucking as themselves.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Conservative','AKA'=>'Traditional, Traditionally ..., Moderate, Neo-phobic, Quiet, Steady, Fussy, Fuddy-duddy, Conventional, Die-hard ..., Fogyish, Hidebound, Holding onto ..., Illiberal, In a rut, Inflexible, Obstinate, Old Guard, Orthodox, Right-Wing, Sober, Unchanging, Unchangeable, Uncreative, Unimaginative, Boring, Bore about ..., Classicist, Obstructionist, Reactionary, "Stick in the Mud", Redneck', 'Facet'=>'Rook', 'Specify'=>1, 'HitchType'=>6, 'Description'=>'Conservative Characters will always have a blockage against certain actions (often defending those they disagree with).', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Savage','AKA'=>'Atrocious, Bloody, Brutal-looking, Brutal, Barbaric, Cold-blooded, Crude, Brutish, Bestial, Lupine, Primeval, Feral, Ferocious, Inhuman, Malevolent, Malicious, Merciless, Monstrous, Murderous, Pitiless, Primordial, Ruthless, Sadistic, Unrestrained, Wolfish', 'Facet'=>'Rook', 'Specify'=>1, 'HitchType'=>7, 'Description'=>'The Savage Hitch can be ideal for roughly hewn Descendants, perhaps those covered in spikes, blades or animal teeth.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Justifiable','AKA'=>'Justifies ..., Justified ..., Uphold ..., Excuse to ..., Letter of Marque, Privateer, Licensed to ..., At War, Self-Defence, Doctrine of Necessity, Warrant of Arrest, Bounty', 'Facet'=>'Rook', 'Specify'=>1, 'HitchType'=>8, 'Description'=>'The Justifiable Hitch can be used whenever a Descendant\'s ownership must be justified, or when a Character will excuse themselves responsibility somehow.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Frustrating','AKA'=>'Thwarting ..., Disappointing ..., Frustrating ..., Discouraging ..., Disheartening ..., "More trouble than they are worth", Trouble-maker, Impedes ..., Counteracts ..., Obstructs ..., Annoying ..., Prohibits ..., "Gives the run around", Hope Dashing', 'Facet'=>'Rook', 'Specify'=>1, 'HitchType'=>9, 'Description'=>'Frustrating Hitches are annoying, they may be more trouble than they are worth, or may just incur the odd additional cost or difficulty when you are working with them, then again they might just create extra work for no reason.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Strife','AKA'=>'Animosity to ..., Bickering, Clash of ..., Controversial, Disagrees with ..., Dispute with ..., Dissension, Friction with ..., Quarrels with ..., Rivalry with ..., Squabbles with ..., Explosive, Fights Back, Difficult to ..., Hassle to ..., Hard to ...', 'Facet'=>'Rook', 'Specify'=>1, 'HitchType'=>10, 'Description'=>'Strife Hitches are useful whenever you might have a Descendant that might fight back, or be as dangerous to itself as others.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Abused','AKA'=>'Abused by ..., ... Abuse, Beaten up, Maltreated by ..., Mistreated by ..., Misused by ..., Molested by ..., Persecuted by ..., Victimised by ..., Violated by ..., Defiled by ..., Depraved, Deprived, Desecrated, Oppressed by ..., Overworked by ..., Reviled by ..., Hated by ..., Exploited by ..., Victim of ..., Preyed upon by ..., Bullied by ..., Suicidal, Self-harming, Self-destructive Behaviour, "Please, don\'t kill me"', 'Facet'=>'Sin', 'Specify'=>1, 'HitchType'=>0, 'Description'=>'The worst of the Persecuted Hitches, the Abuse victim may even self-harm as a release from the harm their abuser is doing to them.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Oppressed','AKA'=>'Oppressed ..., Downtrodden, Enslaved by ..., Distressed by ..., Exploited by ..., Helpless before ..., Persecuted because of ..., Maltreated by ..., Mistreated by ..., Suppressed by ..., Tormented by ..., Tyrannized by ..., Persecuted Religion, Outcast Social Group, Social Outcast, Social Misfit, "No one understands me", Discriminated against', 'Facet'=>'Sin', 'Specify'=>1, 'HitchType'=>1, 'Description'=>'Oppressed Hitches are commonly used to cover religious or social persecution of an oppressed minority.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Victimized','AKA'=>'Victimized by ..., Bullied by ..., Picked on by ..., Taken Advantage of by ..., Coerced by ..., Harassed by ..., Terrorized by ..., Threatened by ..., Tormented by ..., Tortured by ..., Intimidated by ..., Pushed around by ...', 'Facet'=>'Sin', 'Specify'=>1, 'HitchType'=>2, 'Description'=>'A Victimized Hitches are for Characters that are personally persecuted.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Rogue','AKA'=>'... Rogue, Defector from ..., Defected from ..., Informer on ..., Traitor to ..., Renegade ..., Quisling, Deserter from ..., Double-crosser, Betrayer, Rat, Fink, Snake, Sneak, Snitch, Spy for ..., Squealer, Tattle-tale, Treasonist, Two-Timer, Whistle-blower, Stool Pigeon, Back-Stabber, Disloyal ..., Turncoat, Conspirator', 'Facet'=>'Sin', 'Specify'=>1, 'HitchType'=>3, 'Description'=>'The Rogue Hitch is for those Characters that have abandoned their Guild, or have turned on their former masters and friends. It is the Hitch of the Turncoat, Snitch, Traitor and Renegade.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Hunted','AKA'=>'Wanted by ..., "Wanted Dead or Alive", On the Run from ..., Hunted by ..., Chased by ..., Chased from ..., Dogged by ..., Followed by ..., Hounded by ..., Outlawed, Stalked by ..., Tailed by ..., Tracked by ..., Searched for, Suspected of a crime, Target of Genocide, Nemesis, Changed Identity, Witness Protection, Undercover', 'Facet'=>'Sin', 'Specify'=>1, 'HitchType'=>4, 'Description'=>'Hunted Hitches are suitable for Characters that are on the run, hounded by the press and fans, or the only humans dropped on an alien hunting preserve.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Torment','AKA'=>'Teased about ..., Teased by ..., Upset by ..., Harassed by ..., Bothered by ..., Bedevilled by ..., Nagged by ..., Pestered by ..., Vexed by ..., Heckled, Punished by ..., "Driven up the wall by ...", Insulted by ..., Insulted for ..., Picked on by ..., Ridiculed by ..., Ridiculed for ..., Taunted for ..., Taunted by ..., Beaten by ..., Bullied by ...', 'Facet'=>'Sin', 'Specify'=>1, 'HitchType'=>5, 'Description'=>'Torment Hitches can social persecution. It might be some teasing, some name-calling, bullying, even beatings, depending on how bad things get.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Discriminated Against','AKA'=>'Disadvantaged by ..., Hindered by ..., Glass Ceiling, Cannot get Promoted, Discriminated Against because of ..., Unemployable, Too ..., Harassed by ..., Workplace Harassment, Marginalized ..., Harassed ..., Segregated for ..., Unusual Dress, Undue Hardship about ..., Viewed with Suspicion because of ...', 'Facet'=>'Sin', 'Specify'=>1, 'HitchType'=>6, 'Description'=>'The Character is stopped from doing something by the nature of who they are, perhaps they hit the glass ceiling or just cannot get a decent job because of the colour of their hair.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Suppressed','AKA'=>'Suppressed by ..., Abolished by ..., Censored by ..., Cover-up, Banned by ..., Out of Favour with ..., Held-back by ..., Kept Secret by ..., Illegal, Outlawed, Contravenes Several Laws, Highly Illegal, Illicit, Prohibited by ..., Smuggled, Unauthorised, Unlicensed ..., Unlawful, Contraband, Black-Market, Boot-leg, Forbidden ..., Extralegal, Felonious, Shady, Sub-Rosa, "Under-handed", "Under the table", Violation, Proscribed by ..., Unapproved, Third-party, Knock-off', 'Facet'=>'Sin', 'Specify'=>1, 'HitchType'=>7, 'Description'=>'The Suppressed Hitch is useful for Descendants that have been banned, are out of favour with the establishment, or a perhaps an unlicensed, bootlegged, third-party, knock-off.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Cover-up','AKA'=>'Pretext for ..., Illegal, Secret, Secrecy, False-Front, Facade, Cover Story, Subterfuge, Deception, Deceitful, Duplicitous, Fallacious, Fib, Ambiguous, Hoaxed, Fraud, Scam, Hustle, Malarkey, Trickery, Swindling, Trap, Illusionary, Ploy, Decoy, Disguised, Double-Dealt, Intriguing, Antics, Gag, Sleight, Stunt, Sport, Tomfoolery, Jape, Jest, Outwit, Misinform, Taken in by ...', 'Facet'=>'Sin', 'Specify'=>1, 'HitchType'=>8, 'Description'=>'The Cover-up Hitch is for Descendants that need to be kept and used secretly. This might be because the Descendant is illegal, or be because knowing the trick destroys the magic.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Unfair','AKA'=>'Arbitrary, Biased towards ..., Biased Against ..., Cruel, Discriminates Against ..., Dishonest, Immoral, Improper, Racist, Sexist, Bigoted, Cheating, Prejudiced against ..., Unjust, Unprincipled, Shameless, Authoritarian, Crooked, Nepotism, Plays Favourites, Overcharges ..., Blames ..., Hates ..., Homophobic, Xenophobic, Misandry, Misogyny, Petty, Unsporting', 'Facet'=>'Sin', 'Specify'=>1, 'HitchType'=>9, 'Description'=>'An Unfair Hitch may mean a character plays favourites, or even discriminates against a group, perhaps charging them more than their fair share. Then again such discrimination will usually cost someone in customers or friends.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Wrong','AKA'=>'Something Amiss, Something Awry, Inaccurate, Misguided, Mistaken ..., Unsound, Untrue, Erring, Goofed, Miscalculated, Askew, Astray, Counterfactual, Defective, Erratic, Faulty, Inexact, Out of Order, Out of line, Not Right, Rotten, Perverse, Perverted, Reprehensible, Unethical, Corrupt, Base, Crooked, Debauched, Depraved, Evil, Profane, Blameworthy, Naughty, Risqué, Unholy, Wicked, Anachronistic, Ill-Advised, Improper, Unacceptable, Unbecoming, Inapt, Incongruous, Unseemly, Unsuitable', 'Facet'=>'Sin', 'Specify'=>1, 'HitchType'=>10, 'Description'=>'A Wrong Hitch can be used for any Descendant that is somehow wrong, it might be corrupted, anachronistic, hoaxed or faked, but somehow it is a wrong&#39;un.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Irritating','AKA'=>'Irritating ..., Irritates ..., Annoying ..., Provocative, Provoking to ..., Bothersome, Vexatious, Annoys ..., Pesky ..., Troublesome, Nagging, Upsetting, Unpleasant, Irksome', 'Facet'=>'Trial', 'Specify'=>1, 'HitchType'=>0, 'Description'=>'Irritating Hitches usually mean someone who aggravates and annoys others either deliberately or accidentally. Examples include having an annoying voice, or being provocative.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Cruel','AKA'=>'Callous, Evil, Cold-blooded, Harsh, Hateful, Heartless, Inhuman, Inhumane, Merciless, Relentless, Ruthless, Sadistic, Spiteful, Tyrannical, Diabolical, Malevolent, Monstrous, Rancorous, Vengeful, Virulent', 'Facet'=>'Trial', 'Specify'=>1, 'HitchType'=>1, 'Description'=>'Cruel Hitches are best used by tyrannical Characters, such as evil school teachers and mad kings.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Nasty','AKA'=>'Awful, Critical, Crude, Despicable, Dirty, Distasteful, Evil, Horrible, Icky, Malodorous, Noxious, Obscene, Obnoxious, Poison, Repugnant, Sarcastic, Sharp-tongued, Sordid, Spiteful, Squalid, Unpleasant, Vile, Wicked', 'Facet'=>'Trial', 'Specify'=>1, 'HitchType'=>2, 'Description'=>'Nasty Hitches are the Offensive Hitch that you can give almost any evil Character. It can describe everything from sharp-tongued scold to a vile prison torturer, and everything in between.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Profane','AKA'=>'Atheist, Blasphemous, Coarse, Sacrilegious, Godless, Heathen, Idolatrous, Impious, Impure, Infidel, Irreligious, Irreverential, Pagan, Mundane, Unsacred, Unhallowed, Sinful, Debased', 'Facet'=>'Trial', 'Specify'=>1, 'HitchType'=>3, 'Description'=>'The Profane Hitch is intended for those Characters who are a little bit un-sacred. They might be atheists in a religious country, or just be as common as muck.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Ugly','AKA'=>'Awful-looking, Grisly, Grotesque, Hideous, Horrid-looking, Unseemly, Unsightly, Appalling, Bad-looking, Deformed, Disfigured, Foul, Frightful, Gross, Ill-favoured, Loathsome, Misshapen, Monstrous, Repugnant, Repelling, Repulsive, Revolting, Sinister, Wretched', 'Facet'=>'Trial', 'Specify'=>1, 'HitchType'=>4, 'Description'=>'The Ugly Hitch is a unique Offensive Hitch, it can just be that the Hitch makes someone or something Ugly on the outside, but more often Ugliness is not skin deep.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Prejudiced','AKA'=>'Biased against ..., Biased towards ..., Bigot, Bigoted, Bigoted Against ..., Discriminatory, Dogmatic, Inclined against ..., Inclined towards ..., Intolerant of ..., Intransigent, Opinionated about ..., Parochial, Partisan, Racist, Sexist, Xenophobic, Closed-minded, Hidebound, Illiberal, Narrow-Minded', 'Facet'=>'Trial', 'Specify'=>1, 'HitchType'=>5, 'Description'=>'The Prejudiced Hitch simply means that a Character has certain (specified) classes of people and things that they constantly pre-judge, deciding things about others based on their skin tone, genitals or number of tentacles.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Repulsive','AKA'=>'Abhorrent, Creepy, Distasteful, Hateful, Hideous, Odious, Off-Putting, Revolting, Loathsome, Repellent, Repels ..., ', 'Facet'=>'Trial', 'Specify'=>1, 'HitchType'=>6, 'Description'=>'Some people are so offensive that they are repellent to other people. Their repulsive nature acts as a Blockage for them.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Outrageous','AKA'=>'Adult, Barbaric, Barbarous, Brazen, Burning, Crazy, Crying, Defamatory to ..., Disgraceful, Disgusting, Disquieting, Dreadful, Erotic, Excessive, Exorbitant, Extravagant, Flagrant, Ghastly, Glaring, Heinous, Heathen, Horrendous, Horrible, Indecent, Lewd, Nauseating, Obscene, Off-Colour, Offensive, Pornographic, Preposterous, Raunchy, Salacious, Scandalous, Scurrilous, Shocking, Smutty, Steamy, Stupefying, Suggestive, Too Much, Unspeakable, Violent, X-Rated', 'Facet'=>'Trial', 'Specify'=>1, 'HitchType'=>7, 'Description'=>'The Outrageous Hitch can be used whenever a Descendant is Offensive in some way, or simply unbelievable.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Mortify','AKA'=>'Embarrassing ...,  Embarrasses ..., Humiliates ..., Disgraces ..., Humbling ..., Shameful Behaviour, Ridiculous, "Let me take them down a peg"', 'Facet'=>'Trial', 'Specify'=>1, 'HitchType'=>8, 'Description'=>'Mortify Hitches can be used for any sort of embarrassing, or disgraceful behaviour.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Insensitive','AKA'=>'Aloof, Blundering, Boorish, Cheeky, Churlish, Coarse, Cold-hearted, Crass, Crude, Cusses, Curt, Discourteous, Effing and Blinding, Favourite Swear-word ..., Feeling-less, Graceless, Gruff, Hard, Hard-Boiled, Hard-hearted, Heartless, Impertinent, Impolite, Inconsiderate, Indelicate, Inelegant, Insolent, Loutish, Oafish, Obtuse, Philistine, Raw, Rude, Savage, Swears, Stubborn, Tactless, Uncaring, Uncouth, Unkind, Unrefined, Vulgar, "Swears like a ...", ', 'Facet'=>'Trial', 'Specify'=>1, 'HitchType'=>9, 'Description'=>'Insensitive Characters are usually foul-mouthed reprobates, but they can just be accidentally offensive as well as deliberately so. Such people usually incur additional costs as they go through life (like having to apologize constantly).', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Aggressive','AKA'=>'Argumentative, Belligerent, Bellicose, Biting, Bitter, Bold, Cocky, Combative, Competitive, Contrary, Destructive, Domineering, Dynamic, Forceful, Hateful, Hawkish, Hostile, Imperious, Inhospitable, Inimical, Invasive, Malevolent, Malicious, Malignant, Martial, Militant, Military, Nervy, Offensive, Ornery, Pugnacious, Pushy, Quarrelsome, Rancorous, Rapacious, Sassy, Scrappy, Spiteful, Surly, Unfriendly, Unsympathetic, Viperous, Vitriolic, Warlike', 'Facet'=>'Trial', 'Specify'=>1, 'HitchType'=>10, 'Description'=>'The Aggressive Hitch is ideal for weapons and psychotic time-travelling robots.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Uncaring','AKA'=>'Aloof, Apathetic, Blasé, Blind to Suffering, Callous, Cold, Cold-blooded, Cool, Cruel, Deadpan, "Deaf to Pleas", Detached, Disinterested, Dispassionate, Emotionless, Hard-Boiled, Heartless, Impassive, Impersonal, Impervious, Indifferent, Insensitive, Listless, Matter-of-fact, Nonchalant, Passionless, Reserved, Robotic, Soulless, Spiritless, "Stiff Upper Lip", Stone-hearted, Stony, Unaroused, Unaffected, Uncompassionate, Unconcerned, Unemotional, Unfeeling, Unsympathetic', 'Facet'=>'Virtue', 'Specify'=>1, 'HitchType'=>0, 'Description'=>'For some the Apathy Hitch indicates that they are simply Uncaring. They may be aloof, or mean, or simply robotic. Being Uncaring can cause harm to themselves as they are injured by feelings.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Dispassionate','AKA'=>'Apathetic, Bored, Casual, "Can\'t be bothered", Couldn\'t care less", Distant, "Doesn\'t give a damn", Easily Bored, Easy Going, Folksy, Indifferent, Impartial, Laid-back, Listless, Impassive, Incurious, Informal, Mellow, Neutral, Nonpartisan, Passive, Purposeless, Stoic, Unbiased, Uninterested, "What the hell", "Why?", "Why not?"', 'Facet'=>'Virtue', 'Specify'=>1, 'HitchType'=>1, 'Description'=>'Dispassionate Characters never really get into anything. They may lack emotions, or a specific one, or simply be easily bored.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Refrain','AKA'=>'Abstain from ..., Arrested,  Avoids ..., Cease ..., Check,  Curb ..., Desist from ..., Eschews ..., Fence-sitting, Forbear ..., Forgo ..., Halt ..., Inhibit ..., Inhibition against ..., Keep from ..., "On the wagon", Quitting ..., Renounced ..., Resist ..., Restrain ..., Shun ..., "Sitting on the fence",  Spurn ..., Stops ..., "Taken the pledge", Teetotaller, Theme music, Withholding ...', 'Facet'=>'Virtue', 'Specify'=>1, 'HitchType'=>2, 'Description'=>'Refrain Hitches are for Characters who avoid certain things (an occasionally for those who have their own theme music). A celibate or teetotal Character should have at least one Refrain Hitch.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Rapture','AKA'=>'Baked, Blissed out, Bombed, Buzzing, Comatose, Contentment, Content with ..., "Dead to the world", Doped up, Drugged, Drugged-up, Drowsy, Drunk, Ecstatic, Elated with ..., Flying, Inebriated, Insensible, Intoxicated, "In Seventh Heaven", Loaded, "On Cloud Nine", "Out to lunch", "Out of their tree", Plastered, Pissed, Sloshed, Smashed, Somnolent, Stoned, Stupefied, Stupid, Tanked, Torpid, Tripping, Unconscious, Vegged-Out', 'Facet'=>'Virtue', 'Specify'=>1, 'HitchType'=>3, 'Description'=>'Rapture Hitches are intended to mimic Characters who are just incapable of doing much. They might be a blissed out drug user, a quietly sloshed drunk, or be a Comatose victim of an illness or wound, they might even just be a happily settled old warrior who doesn&#39;t want to stir up any trouble. Rapture Hitches are often applied as Wounds from Toxin attacks, and usually have only a limited duration of effect, or indicate a regular occurrence, rather than a single time.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Unambitious','AKA'=>'Apathetic, Backward, Dallying, Diffident, Directionless, Docile, Dull, Easy-Going, Everyday, Folksy, Gentle, Good-for-nothing, Homebody, Homey, Humdrum, Idle, Inattentive, Incompetent, Indifferent, Indolent, Lackadaisical, Laggard, Lagging, Lazy, Lethargic, Lifeless, Loafing, Lowly, Ordinary, Procrastinating, Prosaic, Retired, Reverential, Self-effacing, Servile, Shiftless, Slack, Slothful, Stale, Subservient, Tentative, Tractable, Unenergetic, Unindustrious, Unmotivated', 'Facet'=>'Virtue', 'Specify'=>1, 'HitchType'=>4, 'Description'=>'Just as Ambition can be a Hitch so too can a lack of ambition. It might be because a Character doesn&#39;t believe they are worthy of promotion, or they might be already retired, and have accomplished their life goals.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Hesitant','AKA'=>'Averse to ..., Dawdling, Delaying, Diffident, Disinclined to ..., Faltering, Half-hearted, Halting, Hesitating about ..., Hesitation, Indecisive, Irresolute, Lacks Confidence, Lazy, Loath to ..., Reluctant to ..., Shy of ..., Slow to ..., Tentative, Timid around ..., Timid, Uncertain of ..., Unsure of ..., Unwilling to ..., Vacillating, Wavering', 'Facet'=>'Virtue', 'Specify'=>1, 'HitchType'=>5, 'Description'=>'Those with the Hesitant Hitch are not quick to judge, or actually do much of anything. They may be indecisive, or just slow, perhaps they finally get there, perhaps not.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Half-hearted','AKA'=>'Apathetic, Cool, Impassive, Indifferent, Irresolute, Lacklustre, Listless, Lukewarm, Neutral, Passive, Perfunctory, Spiritless, Tame, Tepid, Unenthusiastic, Uninterested', 'Facet'=>'Virtue', 'Specify'=>1, 'HitchType'=>6, 'Description'=>'A Half-hearted Hitch means a Character is never really committed to completing anything properly, this acts as a blockage on their life.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Humble','AKA'=>'Bashful, Beggarly, Blushing, Chagrined, Chastened, Common, Commonplace, Confused, Content, Contemptible, Courteous, Crushed, Deflated, Demure, Disgraced, Drudge, Easily Embarrassed, Gentle, Humiliated by ..., Ignoble, Inglorious, Insignificant, Little, Low-Born, Low-Ranking, Lowly, Meagre, Measly, Menial, Modest, Obliging, Obscure, Obsequious, Ordinary, Paltry, Petty, Pitiful, Plebeian, Polite, "Prole", Proletarian, Puny, Quiet, Reserved, Respectful, Retiring, Scrub, Seemly, Self-Effacing, Servile, Shabby, Shamed by ..., Shamed for ..., Sheepish, Shy, Simple, Small, Soft-spoken, Sordid, Tentative, Timid, Trivial, Unassuming, Uncouth, Underprivileged, Undistinguished, Unimportant, Unobtrusive, Unpretentious, Vulgar, Wretched', 'Facet'=>'Virtue', 'Specify'=>1, 'HitchType'=>7, 'Description'=>'Some Characters have humble beginnings, and some Descendants are always Humble. It might be low-powered, a non-fully featured trial-version or just a cheaper model.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Worthy','AKA'=>'Admirable, Decent, Deserving of ..., Desirable, Excellent, Exemplary, First-Class, First-Rate, Honest, Honourable, Laudable, Meritorious, Middle-class, No ..., Noble, ... Only, Pleasing, Praiseworthy, Precious, Priceless, Prized, Reliable, Reputable, Respectable, Restricted to ..., Righteous, Right-Minded, Salt-of-the-earth, Satisfying, Top-Drawer, Top-Notch, Trustworthy, Under-class, Upper-class, Valuable to ..., Winner, Winning, Working-class, Worthwhile, Worthy of ...', 'Facet'=>'Virtue', 'Specify'=>1, 'HitchType'=>8, 'Description'=>'A Descendant with the Worthy Hitch may only be used, or perhaps owned by those the Hitch specifies. This might be a particular class, type, or race of person, or a specified individual. Alternately perhaps the Worthy Hitch just makes the Descendant or Character more desired, admired, respected or just expensive, perhaps amongst a certain group, this can make a requirement of public appearances or testing / proving oneself.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Impartial','AKA'=>'Candid, Blunt, Brief, Brusque, Curt, Detached, Disinterested, Dispassionate, Equal, Equitable, Ethical, Even-handed, Explicit, Fair, Fair-Minded, Forthright, Frank, Genuine, Honest, Impersonal, Impolite, Just, "Middle-of-the-road", Moral, Neutral, Nonpartisan, Non-discriminating, Objective, "On-The-fence", Open, Open-Minded, Outspoken, Plain, Pointless, Proper, Proportionate, Reasonable, Right, Rightful, Square, Stable, Straightforward, Trenchant, Truthful, Unbiased, Unbigoted, Uncoloured, Unprejudiced', 'Facet'=>'Virtue', 'Specify'=>1, 'HitchType'=>9, 'Description'=>'The Impartial Hitch indicates someone or a Descendant who goes out of their way to be fair. They may take on additional tasks, or costs and pay Chi directly to remain impartial when necessary.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Hallowed','AKA'=>'Angelic, Anointed, Beatified, Blessed, Celestial, Cherished, Consecrated, Consecrated by ..., Dedicated, Dedicated to ..., Deific, Deistic, Divine, Enshrined, Eternal, Exalted, Heavenly, Holy, Honoured, Inviolable, Godly, Marvellous, Mystical, Numinous, Pious, Pure, Religious, Revered, Revered by ..., Sacramental, Sacred, Sacrosanct, Saintly, Sanctified, Solemn, Spiritual, Superhuman, Supernatural, Theistic, Transcendental, Transmundane, Unearth ly,  Unprofane, Venerated, Venerable', 'Facet'=>'Virtue', 'Specify'=>1, 'HitchType'=>10, 'Description'=>'The Descendant with a Hallowed Hitch is revered, kept safe, hidden away, or usually enshrined somewhere. The Catholic Church wouldn\'t want you turning the Shroud of Turin into a battle standard, for example.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Doomed','AKA'=>'Accursed, Bedevilled by ..., Bewitched by ..., Convicted of.., Cursed to ..., Cursed by ..., Damned by ..., Destiny of ..., Destined to ..., Fated to ..., Foreordained to ..., Hopeless, Karma, Kismet, Lost, Menaced, Nemesis, Predestined to ..., Preordained to ..., Prophesied to ..., Providence', 'Facet'=>'Wyrd', 'Specify'=>1, 'HitchType'=>0, 'Description'=>'The worst of the Doomed Hitches. Maybe the Character&#39;s are cursed by the gods, or the moment of their death has been predicted. But whenever the prophecy or curse kicks in they will be harmed.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Omens','AKA'=>'Augury, Auspices, "Bad Vibes", Birthmark, Boding, Caution, Clued-up, Foreboding, Foreshadowing, Harbinger of ..., Hunch, Hunches, "I\'ve got a bad feeling about this", Indication of ..., Indication that ..., Lacks Free-Will, Omen of ..., Portents, Predicted ..., Predictions, Presage, Premonitions, Presentiment, Prognostic, Prognostication, Prophet, Prophetic Dreams, Prophecy, Sign of ..., Signs, "Signs and Portents", Threat from ..., Vibes, Visions, Visions of ..., Warned about ..., Warnings about ...', 'Facet'=>'Wyrd', 'Specify'=>1, 'HitchType'=>1, 'Description'=>'Characters with an Omens Hitch might be plagued by visions of the future, or just have a mysterious birthmark, some may speak of destiny and fate, and mean it in their presence.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Star-crossed','AKA'=>'Accursed, Bedevilled, Blighted, Catastrophic ..., Cursed to ..., Disastrous ..., Enchanted to ..., Ensorcelled to ..., Hexed by ..., Hexed to ..., Ill-fated ..., Ill-omened ..., Incurable Romantic, Infernal,  Jinxed, Luckless, Misfortune, Unfortunate, Unholy, Unlucky', 'Facet'=>'Wyrd', 'Specify'=>1, 'HitchType'=>2, 'Description'=>'Sometimes fate and the Wyrd have nothing good planned for a Character. Perhaps its a cursed love-life, or ill-luck with money, or bad health. No matter what could happen, it always seems to turn out badly for a Star-crossed Hitch.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Condemned','AKA'=>'blamed by ..., Blamed for ..., Castigated, Censured, Chided, Convicted of ..., Condemned to ..., Condemned for ..., Condemned by ..., Criticized for ..., Criticized by ..., Deja Vu, Denounced for ..., Found Guilty of ..., Guilty of ...,  Imprisoned for ...,  Punished for ..., Sentenced to ..., Reprehended for ...', 'Facet'=>'Wyrd', 'Specify'=>1, 'HitchType'=>3, 'Description'=>'Sometimes Dooms are not a question of Wyrd in her role as fate, but more to do with her role as Justice. The Condemned Hitch can bind a Character in manacles, or leave him to rot in jail, it can even condemn him to death.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Dreams','AKA'=>'Bad Dreams, Brainstorms, Chimerical Existence, Conceive of ..., Conjures up ..., Daydreams, Delusions of ..., Dreams about ...,  Envisages ..., Fancies ...,  Fantasizes about ..., Hallucinates ..., "Hallucinations and Delusions", Idealises ..., Imagines ..., Nightmares about ..., Nightmares, Pictures ..., Phantasms, Phantoms, Precognitive Dreams, Reveries of ..., Sees Visions, Spectres of ..., Spectral Visions, Thinks about ..., Visualises ..., Visits Dreamlands', 'Facet'=>'Wyrd', 'Specify'=>1, 'HitchType'=>4, 'Description'=>'Sometimes a Character seems fine in their day-to-day life, but a Doomed Hitch can affect their sleep instead. Perhaps they dream of another life, in another world, or their dreams come true, or perhaps they have only nightmares when they rest.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Haunted','AKA'=>'Agonizing over ..., Besieged by ..., Frequented by ..., Ghosts of ..., Harassed by ..., Harrowed by ..., Haunted by ..., Hounded by ..., Maddened by ..., Obsessed with ..., Pervading Memories, Phantoms, Preyed upon by ..., Pestered by ..., Reappearances, Returns, Shades of ..., Terrorised by ..., Tormented by ..., Visited by ...', 'Facet'=>'Wyrd', 'Specify'=>1, 'HitchType'=>5, 'Description'=>'A Character with a Haunted Hitch might be haunted by memories of their youth, the choices they once made, a lost love (although that could be a Lament instead). Or they may actually have to go toe-to-toe, or have a heart-to-heart with a ghost or poltergeist.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Jinxed','AKA'=>'Bedevilled, Bewitched, "Can\'t catch a break", Charmed, Condemned, Cursed, Damned, Enchanted, Enraptured, Ensorcelled, Enthralled, Evil Eye, Fascinated, Hexed, Hypnotised, Magical, Mesmerised, Occult, Otherworldly, Possessed, Spelled, Spellbound, Spooky, Sorcerous, Talismanic, Thaumaturgic, Theurgic, Uncanny, "Under a spell", Unlucky, Witching, Woeful', 'Facet'=>'Wyrd', 'Specify'=>1, 'HitchType'=>6, 'Description'=>'A Jinxed character just can\'t catch a break, they constantly find themselves and their destiny is either blocked or working against them.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Prophecy','AKA'=>'Apocalypse, Astrology, Augury, Cast, Divination, Forecast, Foretelling, Fortune-telling, Horoscope, Oracle, Predicted, Prediction, Presage, Prevision, Prognosis, Revelation, Second-Sight, Soothsaying', 'Facet'=>'Wyrd', 'Specify'=>1, 'HitchType'=>7, 'Description'=>'The Prophecy Hitch is useful for slapping on Characters and Descendants that fulfil some grand plan decided by deities, Demons or Yarn-Tellers. They might be named in a specific Prophecy, or believe a Prophecy is about them. They may even be a prophet themselves, creating future Chronoliths that may come to pass.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Weird','AKA'=>'Creepy, Bizarre, Dreadful, Eccentric, Eerie, Freaky, Ghastly, Ghostly, Haunting, Horrific, Inscrutable, Kooky, Mysterious, Occult, Oddball, Ominous, Outlandish, Peculiar, Queer, Singular, Spooky, Strange, Supernal, Supernatural, Uncanny, Unearthly, Unnatural', 'Facet'=>'Wyrd', 'Specify'=>1, 'HitchType'=>8, 'Description'=>'Sometimes a Doomed Hitch just makes something Weird. Weird Hitches are suitable for odd devices and contraptions, dream descendants and anything truly strange or inexplicable.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Forfeit','AKA'=>'Abandoned by ..., Costs ..., Damages, Fined for ..., Loss of ..., Penalty of ..., Relinquishment of ..., Renounce ..., Surrender ..., Sacrifice ..., Hand over ...', 'Facet'=>'Wyrd', 'Specify'=>1, 'HitchType'=>9, 'Description'=>'Forfeit Hitches require a Character to pay for their crimes or bad karma. Usually this is in the form of additional tasks and costs.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Paradoxical','AKA'=>'Adverse, Antithetical to ..., Baffling, Bootstrap Paradox, Byzantine, Catch-22, Circuitous, Complicated, Confusing, Contradictory to ..., Contrary to ..., Controversial, Convoluted, Cryptic, Differing from ..., Disconcerting, Enigmatic, Gordian, Hypothetical, Incongruous, Inconsistent, Inimical, Intricate, Ironic, Mysterious, Mystifying, Philosophical, Predestination Paradox, Problematic, Puzzling, Retrograde, Sardonic, Sarcastic, Ship of Theseus Paradox, Temporal Paradox, Unconnected, Worrying', 'Facet'=>'Wyrd', 'Specify'=>1, 'HitchType'=>10, 'Description'=>'The Paradoxical Hitch is for things that don\'t make a lot of sense. They might be created by a Temporal paradox, or just be nonsensical, or Oxymoronic.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Senseless','AKA'=>'Absurd, Asinine, Batty, Crazy, Daft, Eccentric, Erratic, Fatuous, Flaky, Fool, Foolish, Hare-brained, Idiotic, Illogical, Imbecile, Inane, Incongruous, Inconsistent, Insignificant, Irrational, Loony, Ludicrous, Mad, Meaningless, Mindless, Moron, No Common Sense, Nonsensical, Nutty, Odd, Pointless, Preposterous, Purposeless, Ridiculous, Senselessly Violent, Silly, Simple, Stupid, Trivial, Unimportant, Unintelligent, Unpredictable, Unreasonable, Unwise, Wacky, "Without rhyme or reason"', 'Facet'=>'Yonder', 'Specify'=>1, 'HitchType'=>0, 'Description'=>'Some Characters Loss of Sense Hitches are actually Senseless Hitches, they may be senselessly violent, have No Common Sense, or have a complete loss of sense that leads them to injure themselves. ', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Missing Sense','AKA'=>'Adipsia, Anaphia, Anosmia, Blind, Blinded, Cannot Sense ..., Cataract, Ciliopathy, Colour-blind, Deaf, Deafened, Dizzy, Dysesthesia, Eye Damage, Eye Defect, Hard of Hearing, Hearing Loss, Hypodipsia, Hypoesthesia, Impaired Sensation, Lack of Appetite, Lacks Taste, Lip-reads, Loss of Balance, Missing Sense of ..., No Sense of ..., Numb, "Pins and Needles", Sense Impairment, Smell-blind, Tingling, Tone-deaf, Unbalanced, Unsighted', 'Facet'=>'Yonder', 'Specify'=>1, 'HitchType'=>1, 'Description'=>'Some Characters are blind or deaf, but cope, with their Missing Sense, mostly. They might require focus or be limited or restricted somehow, though.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Poor Sense','AKA'=>'Bifocals, Blurred Vision, "Can\'t make this out, what does it say?", Colour-blind, Contact Lenses, Ear-trumpet, "Eh? What-did-you-say?", Eyeglasses, "Four Eyes", Glasses, Goggles, Hard-of-hearing, Hearing Impaired, Hearing Aid, Hearing-Aid User, Monocle Wearer, Muffled Hearing, Night Blindness, Perforated Eardrum, Pince-nez, Poor Eyesight, Reading Glasses, Shades, "Speak up!", Spectacle Wearer, Spectacles, Tone-Deaf, Vision Impaired, "Wearing sunglasses at night", Wears Glasses,', 'Facet'=>'Yonder', 'Specify'=>1, 'HitchType'=>2, 'Description'=>'If a Loss of Sense is not complete then you are probably after a Poor Sense Hitch (or a Vague Hitch instead). Useful for those Characters that are Myopic without glasses or need a hearing aid.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Lack of Unusual Sense','AKA'=>'Broken Antenna, Cannot Sense ..., Data-blind, Doom-blind, Network-Deaf, No-Signal, Telepathic Projector, Thought-blind, "Where\'s the Zoom on these things?"', 'Facet'=>'Yonder', 'Specify'=>1, 'HitchType'=>3, 'Description'=>'Some lack a Sense that isn&#39;t a common one we all share, but you would expect a Character to have. Like a Doom-blind Eelafin, a Telepath who can only project their thoughts not read others, or a Eusaivean Abehini without wifi connectivity.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Affected Sense','AKA'=>'Always Hungry, Twisted Moral Sense, Dyslexia, Blurred Vision, Tinnitus', 'Facet'=>'Yonder', 'Specify'=>1, 'HitchType'=>4, 'Description'=>'Sometimes the Loss of Sense Hitch actually refers to some sense that is out of whack rather than missing. A Character might be always hungry or have a twisted sense of morals with this Hitch.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Loss of Sense','AKA'=>'Hysteria, Hysterical Blindness, Hysterical Deafness, Incurable Romantic', 'Facet'=>'Yonder', 'Specify'=>1, 'HitchType'=>5, 'Description'=>'Sometimes the only way to describe a Loss of a Sense is as exactly that, even though the cause may be social. A Character might be Oblivious, or suffer from Hysterical Blindness, or be an Incurable Romantic.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Oblivious','AKA'=>'Inattentive, Absent-minded, Disregardful, Not-All-There,', 'Facet'=>'Yonder', 'Specify'=>1, 'HitchType'=>6, 'Description'=>'An Oblivious Character can see what is happening, but some blockage stops them from understanding what they are seeing.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Insensible','AKA'=>'Out-of-Touch, Fanciful, Cognitive Bias, Law-of-the-Instrument, Hammer-rule, Nerdview, Over Specialization, Panacea', 'Facet'=>'Yonder', 'Specify'=>1, 'HitchType'=>7, 'Description'=>'Insensible Hitches are for Characters and Descendants that just seem to have lost touch with reality a little. An example includes how all problems look flammable to a wizard with a fireball spell, or if you only have a hammer all problems look like nails...', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Sacrifice Sense','AKA'=>'Blocks Vision, Restricted Vision, Slit Visor, Blocked Sense, Loud, Tinnitus Inducing, Bright', 'Facet'=>'Yonder', 'Specify'=>1, 'HitchType'=>8, 'Description'=>'Using the Descendant may cost the user access to a sense. Armour may stop them from hearing well, or a gas mask stops scents, guns and amplified instruments can make ears ring too.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Purblind','AKA'=>'Dim-sighted, Partially-blinded, Partially-deaf, Hard-of-Hearing, Hearing-impaired, Vision-Impaired, Corrective lenses, Wears Glasses, Myopic', 'Facet'=>'Yonder', 'Specify'=>1, 'HitchType'=>9, 'Description'=>'Maybe a character wears expensive prescription glasses or contact lenses, or maybe they have to rent a hearing aid or some such device.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Burst','AKA'=>'Deafening, Blinding, Dazzling, Ear-splitting', 'Facet'=>'Yonder', 'Specify'=>1, 'HitchType'=>10, 'Description'=>'The Burst Hitch indicates that the Descendant goes out with a bang. It makes a loud noise and flash that may blind and deafen those around, and using it.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Uncertainty','AKA'=>'Uncertain, Unreliable, Undecided, Ambivalent', 'Facet'=>'Zeal', 'Specify'=>1, 'HitchType'=>0, 'Description'=>'For some with the Doubt Hitch they become Uncertain. Perhaps they are Agnostic, questioning, or unwilling to commit.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
		array('Name'=>'Distrust','AKA'=>'Distrustful, Suspicious, Non-believer, Free-thinker', 'Facet'=>'Zeal', 'Specify'=>1, 'HitchType'=>1, 'Description'=>'Some doubters are just full of Distrust Hitches. They usually Distrust a group or Authority figure, and can be baseless beliefs themselves or might be based on facts.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
