	static public function getSomeHitches(){
		global $post;
		if ($post){
			$current=get_current_user_id();
			$auth=array(0,1,$current);
			 //$author='any',$geo='any',$tags='any',$facet='any',$genre='any',$era='any',$scope='any',$parent='any'

			 $terms['Geo']=T13Types::buildTerms('t13geo', 'Void', $post->ID);
			 $terms['Tags']=get_the_terms($post,'post_tag');
			 $terms['Facet']=T13Types::buildTerms('t13facet', 'All Facets', $post->ID);
			 $terms['Genre']=T13Types::buildTerms('t13genre', 'T13 Core', $post->ID);
			 $terms['Era']=T13Types::buildTerms('t13era', 'Timeless', $post->ID);
			 $terms['Scope']=T13Types::buildTerms('t13scope', 'Omniversal', $post->ID);
			 $terms['Data']=T13Types::buildTerms('t13data', 'HitchData', $post->ID);
			 $terms['Parent']=$post->ID;
		}
		$any='any';
		if (!is_array(self::$hitchesArray)){
			$tempArray=T13Types::getT13Elements('Hitches', $terms, 'Array', 5, 'OR');
			 $temp = array();
			foreach ($tempArray as $key=>$val){
				$temp[]=serialize($val);
			}
			$temp=array_unique($temp);
			$hitches=array();
			foreach ($temp as $key=>$val){
				$hitches[]=unserialize($val);
			}
			self::$hitchesArray=$hitches;
		}
		 return self::$hitchArray;
	 }
	static public function getHitchTier($bane,$boon){
		$boon=T13Boons::getBoonAbsolute($boon);
		if (is_numeric($boon)){
		    if (($boon/2)>=$bane){$htier=0;}
		    elseif ($boon>=$bane) {$htier=1;}
		    elseif ($boon<$bane){$htier=2;}
		}
		return $htier;
	}
	static public function getHitchTierText($bane,$boon){
		$tiers=['Quirk','Flaw','Woe'];
		return $tiers[self::getHitchTier($bane,$boon)];
	}
	static public function displayHitch ($hitch,$alt=0){
		$ret=array('Text'=>'','Bane'=>0,'Tier'=>0,'Facet'=>0, 'Resolved'=>0, 'debug'=>'');
		$hback=$hitch;
		if (is_string($hitch)){
			//see if its json
			if (T13Types::is_Json($hitch)){
				$ret['debug'] .= ' json ='. $hback;
				$hitch = json_decode($hback);
			}else{
				//see if it is a title but isn't finished yet
				if (isset($hitch['Name'])&&!isset($hitch['Description'])){
					$hitch = T13Elements::T13ElementExists($hitch['Name'],false);
				}

				$ret['debug'] .= ' loaded = '.$hback;
			}

		}
		if (is_numeric($hitch)){
			// this is a hitch element
			//get it display it?
			$ret['debug'].= ' numeric ='.$hitch;
			$ret['Text'] ='hitch ='.$hitch; //this doesn't work yeet...

			$hitchObj=T13Elements::getT13Element('Hitch', $hitch);
			$name = T13Geometry::writeName($hitchObj['Element']->post_title);
			$description = $hitchObj['Element']->post_content;
			$date = $hitchObj['Date'];
			$css = $hitchObj['CSS'];
			$facet = $hitchObj['Facet'];
			$header = $hitchObj['HTML-header'];
			$footer = $hitchObj['HTML-footer'];
			$gnarls= $hitchObj['Gnarls'];
			$prof_id = $hitchObj['post_is'];
			$earl = $hitchObj['URL'];
			$ret['Text'] = self::buildHitchHTML($ret['Resolved'], $hitch['Facet'],$hitch['Name'],$hitch['Bane'],$hitch['Description'],$hitch['Profs'], $ret['Tier'], $gnarls,$alt, $css, $earl, $date);
		}
		if (is_array($hitch)){
			$ret['debug'] = ' array ='.json_encode($hitch);
			$ret['Bane'] = $hitch['Bane'];
			$charBoon=T13Statblock::getBoonForFacet($hitch['Facet'],$alt);
			$gnarls= 1+self::getHitchTier($hitch['Bane'],$charBoon);
			$ret['Tier'] = self::getHitchTierText($hitch['Bane'],$charBoon);
			$ret['Facet'] = isset($hitch['Facet'])?$hitch['Facet']:$hitch['Profs'][0]['Facet'];
			$ret['Resolved'] = isset($hitch['Resolved'])?$hitch['Resolved']:0;
			//$ret['Text'] = 'hitch ='.json_encode($hitch); // this should change...
			$datestamp =  date_i18n( __( 'l jS \o\f F Y', 'textdomain' ) );
			$currentUser=get_current_user_id();
			$user = T13Types::displayUser($currentUser);
			$date ="<small><p class=\"t13ne-postdata\"><span class=\"t13ne-date\">Posted : {$datestamp}.</span></p><p class=\"t13ne-author\"> Created by: {$user}</p></small>";
			$facets = isset($ret['Facet'])?T13Types::arrayify($ret['Facet']):'all';
			$facets = T13Facets::getTheseFacets($facets);

			$ftext = '';
			$faceT='';
			foreach($facets as $facet){
				$ftext .= ' t13ne-'.T13Types::csser($facet['FacetName']);
				$faceT .= "<div class=\"t13ne-facet\">[t13ne type=\"facet\" facet=\"{$facet['FacetIndex']}\" mode=\"fancy\" /]</div>";
			}
			$geo = T13Geometry::writeGeo($hitch['Name']);
			$name = $geo['GeoText'];
			$geon = intval($geo['BaseGeoNum']);
		//var_dump($facet);
			$geom = 't13ne-geo-geo'.$geon.(($geon>9)?' t13ne-geo-geo'.($geon-9):'');
			$css=' t13ne-type-prof '.$ftext.' t13ne-genre-xp t13ne-era-unknown '.$geom.' t13ne-scope-dev';

			$earl = '#local-proficiency'.md5(json_encode($hitch));
			$ret['Text'] = self::buildHitchHTML($ret['Resolved'], $hitch['Facet'],$name,$hitch['Bane'],$hitch['Description'],$hitch['Profs'], $ret['Tier'], $gnarls,$alt, $css, $earl, $date);
			$ret['Profs'] = $hitch['Profs'];
			//var_dump($ret);
		}
		return $ret;
	}
	static public function buildHitchHTML($resolved=4,$facet='awe',$name='name',$bane=0, $content='content default', $profs=array(), $tier='Quirk', $gnarls=array(),$alt=0, $css='el-default', $earl='/', $date=''){
		$ltier = strtolower($tier);
		$header ='<!-- wp:t13ne-element --><article class="t13ne-element '.$css.'"><div class="t13ne-scope-styler"><div class="t13ne-genre-styler"><div class="t13ne-era-styler"><div class="t13ne-facet-styler"><div class="t13ne-tag-styler"><div class="t13ne-cat-styler"><div class="t13ne-geometry-styler"><div class="t13ne-type-styler"><img id="T13Logo" name="T13Logo" />';
			$footer ='</div></div></div></div></div></div></div></div></article>';
		$rethtml="{$header}<section class=\"t13ne-hitch t13ne-{$ltier}\">";
		$facet = T13Facets::getThisFacet($facet, false);
		switch($resolved){
			case 0:
			$rethtml.='<details class="t13ne-hitch-details"><summary><strong class="t13ne-hitchtitle">Hitch: </strong><strong class="t13-hitch-name"><a href="'.$earl.'"><span class="t13ne-title">'.$name.'</span> <span class="t13ne-multiply"> &times; </span>';
			$rethtml.=T13Boons::writeFullBoon($bane, true, true, false);
			$rethtml.=' <span class="t13ne-tier">('.$tier.')</span> ';
			$rethtml.='</a></strong></summary></summary>';
			$rethtml.='<div class="t13ne-postdata">'.$content.'</div>';
			$rethtml.=' <span class="t13ne-facet-hitch" data-facet="'.$facet['FacetIndex'].'"><strong> Hitch Type: </strong>'.$facet['Hitch'].' ('.$facet['FacetName'].' Hitch)</span><div class="t13ne-facet-hitch-text">'.$facet['Hitch_Text'].'</div><div class="t13ne-hitch-rules"><strong>Rules:</strong>'.$facet['Hitch_Rules'][$tier].'</div>';

			break;
			case 1:
			$rethtml.='Resolved Hitch (Persona): </strong>';
			$rethtml.=' <span class="t13ne-title t13ne-strikethrough"> &ldquo;'.T13Geometry::writeName($name).'&rdquo; </span>';
			$rethtml.="[t13ne type=\"persona\" persona=\"{$facet['Persona']['Name']}\" /]";
			break;
			case 2:
			$rethtml.='Resolved Hitch (Core): </strong>';
			$rethtml.=' <span class="t13ne-title t13ne-strikethrough"> &ldquo;'.T13Geometry::writeName($name).'&rdquo; </span>';
			$rethtml.="[t13ne type=\"core\" core=\"{$facet['Core']}\" /]";
			break;
			case 3:
			$rethtml.='Resolved Hitch (Edge): </strong>';
			$rethtml.=' <span class="t13ne-title t13ne-strikethrough"> &ldquo;'.T13Geometry::writeName($name).'&rdquo; </span>';
			$rethtml.="[t13ne type=\"resolved\" resolved=\"{$facet['Resolved_Hitch']}\" /]";
			break;
			case 3:
			$rethtml.='Resolved Hitch (Monster): </strong>';
			$rethtml.=' <span class="t13ne-title t13ne-strikethrough"> &ldquo;'.T13Geometry::writeName($name).'&rdquo; </span>';
			$rethtml.="[t13ne type=\"monster\" monster=\"{$facet['Monster']}\" /]";
			break;
			default:
			$rethtml.='Resolved Hitch: </strong>';
			$rethtml.=' <span class="t13ne-title t13ne-strikethrough"> &ldquo;'.T13Geometry::writeName($name).'&rdquo; </span>';
			$rethtml.="[t13ne type=\"resolved\" resolved=\"{$facet['Resolved_Hitch']}\" /]";
			break;

		}
		//var_dump($profs);
		$profData = T13Proficiencies::profLister($profs,T13Boons::getBoonReduced($bane), true,'',$alt, false);
		$rethtml.= $profData['HTML'];
		unset($profData);

		$rethtml.='</details></section>'.$date.$footer;
		return $rethtml;
	}
    static public function displayHitchSC($hand, $handBoon=10, $boon='%%', $alt=0, $resolved=0){
	//var_dump($hand);
	//shortcode hitch display...
	$rethtml="<!-- hitch:{$hand} x{$handBoon} vs.{$boon} for {$alt} //-->";
	if ( ! function_exists( 'wp_get_recent_posts' ) ) {
		//if posts exists doesn't load it.
			 require_once( ABSPATH . 'wp-includes/post.php' );
		}
		if (!is_numeric($alt)){
			$alter=T13Types::getT13Element('Char',$alt);
			$alt=$alter['post_id'];
		}
	$hsr=T13Types::getT13Element('Hitch',$hand);
	$rethtml.=$hsr['HTML-header'];
	$facet=$hsr['Facet'];

	if ($facet=='%'){$facet=T13Facets::getFacet('Miasma','array');}
	$displayFacet=T13Facets::getFacet($facet[0],'fancy');
	if ($boon=="%%"){
		$boonArr=T13Statblock::getBoonForFacet($facet[0]['FacetIndex'],$alt);
		$boon=$boonArr['Scale']+$boonArr['Boon'];
		$boonJ=json_encode($boonArr);
	}

	    if (is_numeric($boon)){
		    if (($boon/2)>=$handBoon){$htier=0;}
		    elseif ($boon>=$handBoon) {$htier=1;}
		    elseif ($boon<$handBoon){$htier=2;}
		    $hitchTier=T13Types::$hitchTiers[$htier];
		    $hcss='t13ne-'.strtolower($hitchTier['Tier']);

			if ($resolved){
				if (is_string($resolved)){
					foreach (self::$resolves as $r){
						if ($r['Name']==$resolved){
							$resolved=$r['Index'];
						}
					}
				}
			}
			if (!is_wp_error($hsr['Element'])){
				if (is_numeric($resolved)){
					$rethtml.="<section class=\"t13ne-hitch\"><strong class=\"t13ne-hitchtitle\">";
					switch($resolved){
						case 0:
						$rethtml.='Hitch: </strong><details><summary>';
						$rethtml.=' <span class="t13ne-facethitch" data-facet="'.$facet[0]['FacetIndex'].'">'.$facet[0]['Hitch'].' ('.$facet[0]['FacetName'].') ';
						$rethtml.=' <span class="t13ne-title"> &ldquo;'.$hsr['Element']->post_title.'&rdquo; </span>';
						$rethtml.=' <span class="t13ne-multiply"> &times; </span>';
						$rethtml.=T13Boons::writeFullBoon($handBoon, false);
						$rethtml.='</summary>';

						//$tier=do_shortcode("[t13ne type=\"select\" select=\"hitchtier\" selected=\"{$htier}\" /]");
						$content=do_shortcode($hsr['Element']->post_content);
						//$content = str_replace('<t13ne-hitch-tier/>',$tier, $content);
						$rethtml.='<div class="t13ne-postdata">'.$content.'</div>'.$hsr['Date'].'</details>';
						break;
						case 1:
						$rethtml.='Resolved Hitch (Persona): </strong>';
						$rethtml.=' <span class="t13ne-title t13ne-strikethrough"> &ldquo;'.$hsr['Element']->post_title.'&rdquo; </span>';
						$rethtml.="[t13ne type=\"persona\" persona=\"{$facet['Persona']['Name']}\" /]";
						break;
						case 2:
						$rethtml.='Resolved Hitch (Core): </strong>';
						$rethtml.=' <span class="t13ne-title t13ne-strikethrough"> &ldquo;'.$hsr['Element']->post_title.'&rdquo; </span>';
						$rethtml.="[t13ne type=\"core\" core=\"{$facet['Core']}\" /]";
						break;
						case 3:
						$rethtml.='Resolved Hitch (Edge): </strong>';
						$rethtml.=' <span class="t13ne-title t13ne-strikethrough"> &ldquo;'.$hsr['Element']->post_title.'&rdquo; </span>';
						$rethtml.="[t13ne type=\"resolved\" resolved=\"{$facet['Resolved_Hitch']}\" /]";
						break;
						case 3:
						$rethtml.='Resolved Hitch (Monster): </strong>';
						$rethtml.=' <span class="t13ne-title t13ne-strikethrough"> &ldquo;'.$hsr['Element']->post_title.'&rdquo; </span>';
						$rethtml.="[t13ne type=\"monster\" monster=\"{$facet['Monster']}\" /]";
						break;
						default:
						$rethtml.='Resolved Hitch: </strong>';
						$rethtml.=' <span class="t13ne-title t13ne-strikethrough"> &ldquo;'.$hsr['Element']->post_title.'&rdquo; </span>';
						$rethtml.="[t13ne type=\"resolved\" resolved=\"{$facet['Resolved_Hitch']}\" /]";
						break;

					}
				}

				$rethtml.='</section>'.$hsr['HTML-footer'];
				return $rethtml;
			}else{
				return json_encode($hsr['Element']).$hsr['HTML-footer'];
			}
		}else{
			return false;
		}
    }
