    static public function addHitch($name='Unnamed Hitch', $aka='No Aliases', $facet=0, $specific=false, $hitchtype=0, $description='Default Description of the Hitch', $genre='Experimental', $era='Unknown', $scope = 'Development', $hboon=0, $htier=0, $charID=null){
	//array('Name'=>'Transmundane','AKA'=>'', 'Facet'=>'Zeal', 'Specify'=>1, 'HitchType'=>7, 'Description'=>'A Descendant with this Hitch is of doubtful existence. Perhaps it is delusionary somehow, or supernatural in nature. It might be the result of magic in a low-magic universe, or science in a low-science universe.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
	$facethitchtype = T13Facets::$facets[T13Facets::getFacetIndex($facet)]['Hitch'];
	if (is_numeric($hitchtype)){
		$type=T13Types::$hitchTypes[$hitchtype]['Type'];
	}
	if (is_string($name)){
		$name = T13Elements::titleFromNames(array($name, "{$facethitchtype} {$type} {$name} Hitch", "{$aka}, {$facet} Hitch"), $specific);
	}
	if (is_numeric($charID)){
		$charBoon=T13Statblock::getBoonForFacet($facet,$charID);
		$statID = T13Statblock::getStatID($charID);

	}
	$terms=array('Type'=>['Hitch','Knot'], 'Facet'=>$facet, 'Genre'=>$genre,'Scope'=>$scope,'Era'=>$era, 'Data'=>['HitchData','hitchtype'.$hitchtype]);
	if ($hboon>0&&isset($charBoon)){
		if ($hboon>$charBoon){
			//whoa its a woe
			$terms['Data'][]='Woe';
			$htier = 2;
		}else{
			if (($charBoon/2)<$hboon){
				//flaw
				$terms['Data'][] = 'Flaw';
				$htier =1;
			}else{
				//quirk
				$terms['Data'][] = 'Quirk';
				$htier = 0;
			}
		}
	}
		//array('Name'=>'Mortify','AKA'=>'', 'Facet'=>'Trial', 'Specify'=>1, 'HitchType'=>7, 'Description'=>'Mortify Hitches can be used for any sort of embarrassing, or disgraceful behaviour.', 'Genre'=>'T13 ore', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ), 'Quirk', 'Flaw', 'Woe']);
		$post_id_array=T13Elements::addT13Element('Hitch', $name, array('Description'=>$description,'HBoon'=>$hboon, 'HitchType'=>$hitchtype, 'HitchTier'=>$htier, 'ElementID'=>$charID, 'StatID'=>$statID ), $terms, true,0 );

    }
    static public function tieHitch($hitchid, $targetid, $hboon=0, $resolvedTier=0 ){
	// right this should check that the hitchid is the id of a hitch.
	if (T13Types::checkType('Hitch', $hitchid)){
		$hitch = T13Elements::getT13Element('Hitch',$hitchid);

		if (isset($hitch['Facet'])&&$hboon){
			// then it should calculate the Tier
			$boon = T13Statblock::getBoonForFacet($hitch['Facet'],$targetid);
			$statid=T13Statblock::getStatID($targetid);
			if ($resolvedTier=0&&$hboon>0&&is_numeric($boon)){
					if ($hboon>$boon){
					//whoa its a woe
					$htier = 2;
					}else{
					if (($boon/2)<$hboon){
						//flaw
						$htier =1;
					}else{
						//Quirk
						$htier = 0;
					}
				}
			}else{
				//resolved...
				if (is_numeric($resolvedTier)&&$resolvedTier>2&&$resolvedTier<7){
					$htier = $resolvedTier;
				}else{

					foreach(T13Types::$hitchTiers as $in => $tier){
						if ($tier['Tier']===$resolvedTier||strtolower($resolvedTier)==$tier['Direction']){
								$htier=$in;
							}
					}
				}
			}
			$tier = T13Types::$hitchTiers[$htier];
			if (T13Types::checkType('Pact',$targetid)){
				$group = T13Thresholds::getGroupID($targetid);
			}else{
				$group= null;
			}

				// and tie the appropriate threshold.
			$threshold=T13Thresholds::tieThreshold('hitchtier', $tier['Direction'], "Added Hitch {$hitchid} to Element {$targetid}. Automatically created {$tier['Tier']} Threshold for a hitch boon of ({$hboon}). This should be checked each loading in case values change until it has been resolved.", $hitchid,$targetid,$group,$statid, $hitch['Facet'], $hboon, false,null);
			return array('Tier'=>$htier, 'Threshold'=>$threshold);

			}
		}
    }


    static public function hitchContent($name,$hitch,$data,$publish){
	//$tier,$geo, $description

	$tier='Not set';

	if (isset($hitch['HitchType'])){$type=$hitch['HitchType'];}elseif (isset($hitch['Type'])){$type=$hitch['Type'];}
	    if (isset($hitch['HitchTier'])){$tier=$hitch['HitchTier'];}

	$typeno = $type;
	$type=T13Types::$hitchTypes[$type];
		//error_log('hitchContent:: type='.json_encode( $type ));
		if (is_numeric($tier)){
			$tier = T13Types::$hitchTiers[$tier];
		}
		$terms=$data['Terms'];
		$terms['Facet']=$hitch['Facet'];

		//automatically add a Proficiency for the Hitch
		$profnames = T13Elements::namesFromTitle($name);
		$profData=array_merge($hitch,$data);
		$profData['Description']="A Proficiency for the ".$profnames[0].' Hitch. '.$hitch['Description']."<small class=\"t13ne-disclaimer\">This Proficiency was added automatically when adding the Hitch <a href=\"{$data['URL']}\" data-post-id=\"{$data['post_id']}\">&ldquo;{$profnames[1]}&rdquo;. </small>";

		$profterms = $terms;
		$profname = T13Elements::AlternateName('Proficiency', $name);
		$profterms['Data']=[];
		$profterms['Parent']=$data['post_id'];
		$prof=T13Elements::addT13Element('Proficiency', $profname, $profData, $profterms, $publish, 1);
		//create a created/ creator
		$threshold = array(T13Thresholds::tieThreshold('creator', 'owns', "Automatically created proficiency {$profname} for a Hitch. Indicates ownership by target element.", $data['post_id'],$prof['post_id'],null,null, $hitch['Facet'], null, false,null));
		if (is_array($type)){
			$threshold[]=T13Thresholds::tieThreshold('hitch', $type['Direction'], "Automatically created Type ({$type['Type']}) Threshold for a Hitch.", $data['post_id'],$data['post_id'],null,null, $hitch['Facet'], null, false,null);
		}
		if (is_array($tier)&&isset($data['ElementID'])){
			//the tier is preset and we have an Element that wants to own (a copy of) the Hitch.
			if (!isset($data['StatID'])){
				$data['StatID']==T13Statblock::getStatID($data['ElementID']);
				//if stats aren't set then the tier may be incorrect.
				$charBoon=T13Statblock::getBoonForFacet($hitch['Facet'],$data['ElementID']);
				if ($hitch['HBoon']>0&&isset($charBoon)){
					if ($hitch['HBoon']>$charBoon){
						//whoa its a woe
						$terms['Data'][]='Woe';
						$htier = 2;
					}else{
						if (($charBoon/2)<$hitch['HBoon']){
							//flaw
							$terms['Data'][] = 'Flaw';
							$htier =1;
						}else{
							//Quirk
							$terms['Data'][] = 'Quirk';
							$htier = 0;
						}
					}
					$htier = T13Types::$hitchTiers[$htier];
					if (!T13Types::contains($tier['Tier'], "Resolved") && $tier['Direction']!==$htier['Direction'] ){
						//not resolved and calculated as wrong... update.
						$tier = $htier;
					}
				}
			$threshold[]=T13Thresholds::tieThreshold('hitchtier', $tier['Direction'],"Automatically created Tier {$tier['Tier']} Threshold for the {$name} Hitch and element {$data['ElementID']}. This should be checked each loading in case values change until it has been resolved.", $data['post_id'],$data['ElementID'],null,$data['StatID'], $hitch['Facet'], $hitch['HBoon'], false,null);
			}
		}
		if (is_array($tier)&&is_array($type)){
			$terms['Data']=array('HitchData','hitchtype'.$typeno, $tier['Tier']);
		}

		//error_log("hitch terms:".json_encode($terms));
		return array('Content'=>$hitch['Description'], 'Prof'=>$prof, 'Terms'=>$terms,'Thresholds'=>$threshold);

