    static public function installHitches(){
	if ( ! function_exists( 'post_exists' ) ) {
		//if posts exists doesn't load it.
			 require_once( ABSPATH . 'wp-admin/includes/post.php' );
		}

		$c=count(self::$coreHitches);

		$installed=array('hitch'=>0, 'of'=>$c, 'install'=>0);
	foreach(self::$coreHitches as $core){
		$facethitchtype = T13Facets::$facets[T13Facets::getFacetIndex($core['Proficiencies']['HitchType']['Facet'])]['Hitch'];
		$facetgnarl = T13Facets::$facets[T13Facets::getFacetIndex($core['Proficiencies']['Gnarls'][0]['Facet'])]['Gnarl'];
		//$type=T13Types::$hitchTypes[$core['HitchType']]['Type'];
		$names = array($core['Name'], "{$facethitchtype} {$core['Name']} Hitch", "{$core['AKA']}, {$core['Facet']} Hitch");
		if (T13Elements::T13ElementExists($names, $core['Specify'] )){
				error_log("installing Hitches Hitch Found");
			//$installed['hitch']=$name;
			$installed['install']++;
		}else{
				error_log("installing Hitch {$names[0]}");
			$installed['hitch']=$names[0].' '.$names[1];
			$installed['install']+=self::installHitch($installed['install']);
			return $installed;
		}

	}
	return $installed;
    }
	static private function installHitch($install){
		if (count(self::$coreHitches)>$install){

			$core=self::$coreHitches[$install];
			$facet = T13Facets::$facets[T13Facets::getFacetIndex($core['Facet'])];
			$facethitchtype = $facet['Hitch'];
		$typer=T13Hitches::$hitchTypes[$core['HitchType']];
		$type = $typer['Type'];
		$tiers = array('Quirk', 'Flaw','Woe');
		$ttext= '<!-- wp:list {"className":"t13ne-hitch-tiers"} -->
		<ul class="t13ne-hitch-tiers">';
		foreach ($tiers as $tier) {
			$css=strtolower($tier);
			$ttext .= "<li class=\"t13ne-{$css}\">{$typer[$tier]}</li>";
		}
		$ttext.= "<li class=\"t13ne-resolved t13ne-resolved-hitch\"><strong>{$facet['Resolved_Hitch']}</strong> — <span class=\"t13ne-resolved-text t13ne-description\">{$facet['Resolved_Text']}</span></li></ul>
		<!-- /wp:list -->";
		$core['Description'] = '<!-- wp:group {"className":"t13ne-hitch"} -->
		<div class="t13ne-hitch">
		<!-- wp:html -->
		<div class="t13ne-hitch-details t13ne-description">'.$core['Description'].'</div>
		<!-- /wp:html -->
		<!-- wp:html -->
		<div class="t13ne-hitch-type">This Hitch is of the <em>'.$type.'</em> Type. '.$typer['Description'].'</div>
		<!-- /wp:html -->
		'.$ttext.'
		<!-- /wp:group -->';
		$core['FullName']="The Core {$core['Name']} {$type} {$facethitchtype} Hitch";
		$core['AKA'] .= ", Core {$core['Facet']} Hitch";
		$name = T13Elements::titleFromNames(array($core['Name'], $core['FullName'], $core['AKA']), $core['Specify']);
			//array('Name'=>'Mortify','AKA'=>'', 'Facet'=>'Trial', 'Specify'=>1, 'HitchType'=>7, 'Description'=>'Mortify Hitches can be used for any sort of embarrassing, or disgraceful behaviour.', 'Genre'=>'T13 Core', 'Era'=>'Timeless', 'Scope'=>'Omniversal' ),
			$terms=array('Facet'=>$core['Facet'], 'Genre'=>$core['Genre'],'Scope'=>$core['Scope'],'Era'=>$core['Era'], 'Data'=>['HitchData','hitchtype'.$core['HitchType'], 'gnarl1:'.$core['Proficiencies']['Gnarls'][0]['Facet'],'gnarl2:'.$core['Proficiencies']['Gnarls'][1]['Facet'],'gnarl3:'.$core['Proficiencies']['Gnarls'][2]['Facet'],'hitchtier0','hitchtier1','hitchtier2','Quirk', 'Flaw', 'Woe']);
			$post_id_array=T13Elements::addT13Element('Hitch', $name, $core, $terms, 1,0 );
			return 1;
		}
	}
